import type { FC } from 'react';
import { useState, useRef, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { chatService } from '../../services/chatbotService';
import type { ChatMessage } from '../../services/chatbotService';
import { useAuth } from '../../hooks/useAuth';

export const ChatAssistant: FC = () => {
    const { t } = useTranslation();
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState<ChatMessage[]>([
        { role: 'assistant', content: t('chat.welcome') }
    ]);
    const [input, setInput] = useState('');
    const [loading, setLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const navigate = useNavigate();
    const location = useLocation();
    const { user } = useAuth();

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const handleSend = async () => {
        if (!input.trim() || loading) return;

        const userMsg: ChatMessage = { role: 'user', content: input };
        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setLoading(true);

        try {
            const response = await chatService.sendMessage(input, {
                churchId: user?.churchId || 1,
                currentPath: location.pathname
            });

            const assistantMsg: ChatMessage = {
                role: 'assistant',
                content: response.answer,
            };

            // If there's an action, we could attach it to the message or handle it immediately
            // For now, let's treat actions as buttons in the message
            if (response.actions && response.actions.length > 0) {
                // In a real implementation, we'd handle multiple actions. 
                // Let's just show the first one as a button for simplicity in this version.
                assistantMsg.action = response.actions[0];
            }

            setMessages(prev => [...prev, assistantMsg]);
        } catch (error) {
            setMessages(prev => [...prev, {
                role: 'assistant',
                content: t('chat.error')
            }]);
        } finally {
            setLoading(false);
        }
    };

    const handleAction = (action: NonNullable<ChatMessage['action']>) => {
        if (action.type === 'navigate') {
            navigate(action.payload);
            setIsOpen(false);
        } else if (action.type === 'link') {
            window.open(action.payload, '_blank');
        }
    };

    return (
        <>
            {/* FAB Button */}
            <button
                onClick={() => setIsOpen(!isOpen)}
                style={{
                    position: 'fixed',
                    bottom: '90px',
                    right: '24px',
                    width: '56px',
                    height: '56px',
                    borderRadius: '50%',
                    backgroundColor: 'var(--color-brand-blue)',
                    color: 'white',
                    border: 'none',
                    padding: 0,
                    margin: 0,
                    boxShadow: '0 4px 20px rgba(29, 78, 216, 0.4)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    cursor: 'pointer',
                    zIndex: 1000,
                    flexShrink: 0,
                    overflow: 'hidden',
                    transition: 'all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275)',
                    transform: isOpen ? 'rotate(90deg) scale(0.9)' : 'rotate(0) scale(1)',
                }}
            >
                <span className="material-symbols-outlined">
                    {isOpen ? 'close' : 'smart_toy'}
                </span>
            </button>

            {/* Chat Window */}
            {isOpen && (
                <div style={{
                    position: 'fixed',
                    bottom: '160px',
                    right: '24px',
                    width: 'calc(100vw - 48px)',
                    maxWidth: '400px',
                    height: '500px',
                    maxHeight: '60vh',
                    backgroundColor: 'var(--color-card-bg)',
                    borderRadius: '24px',
                    boxShadow: '0 10px 40px rgba(0,0,0,0.15)',
                    display: 'flex',
                    flexDirection: 'column',
                    overflow: 'hidden',
                    zIndex: 1000,
                    border: '1px solid var(--color-border-subtle)',
                    backdropFilter: 'blur(10px)',
                    animation: 'slideIn 0.3s ease-out'
                }}>
                    <style>{`
                        @keyframes slideIn {
                            from { opacity: 0; transform: translateY(20px) scale(0.95); }
                            to { opacity: 1; transform: translateY(0) scale(1); }
                        }
                    `}</style>

                    {/* Header */}
                    <div style={{
                        padding: '20px',
                        background: 'linear-gradient(135deg, var(--color-brand-blue), #3b82f6)',
                        color: 'white',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '12px'
                    }}>
                        <div style={{
                            width: '40px',
                            height: '40px',
                            borderRadius: '20px',
                            backgroundColor: 'rgba(255,255,255,0.2)',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center'
                        }}>
                            <span className="material-symbols-outlined">robot_2</span>
                        </div>
                        <div>
                            <h3 style={{ margin: 0, fontSize: '16px', fontWeight: 600 }}>Asistente MinistryHub</h3>
                            <p style={{ margin: 0, fontSize: '12px', opacity: 0.8 }}>{t('chat.online')}</p>
                        </div>
                    </div>

                    {/* Messages */}
                    <div style={{
                        flex: 1,
                        padding: '20px',
                        overflowY: 'auto',
                        display: 'flex',
                        flexDirection: 'column',
                        gap: '8px'
                    }}>
                        {messages.map((msg, idx) => (
                            <div key={idx} style={{
                                alignSelf: msg.role === 'user' ? 'flex-end' : 'flex-start',
                                maxWidth: '85%',
                            }}>
                                <div style={{
                                    padding: '12px 16px',
                                    borderRadius: msg.role === 'user' ? '18px 18px 2px 18px' : '18px 18px 18px 2px',
                                    backgroundColor: msg.role === 'user' ? 'var(--color-brand-blue)' : 'var(--color-ui-surface)',
                                    color: msg.role === 'user' ? 'white' : 'var(--color-ui-text)',
                                    fontSize: '14px',
                                    lineHeight: '1.4',
                                    boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
                                }}>
                                    {msg.content}
                                </div>

                                {msg.action && (
                                    <button
                                        onClick={() => handleAction(msg.action!)}
                                        style={{
                                            marginTop: '8px',
                                            padding: '8px 16px',
                                            borderRadius: '12px',
                                            backgroundColor: 'var(--color-ui-surface)',
                                            color: 'var(--color-brand-blue)',
                                            border: '1px solid var(--color-brand-blue)',
                                            fontSize: '12px',
                                            fontWeight: 600,
                                            cursor: 'pointer',
                                            display: 'flex',
                                            alignItems: 'center',
                                            gap: '4px',
                                            transition: 'all 0.2s'
                                        }}
                                        onMouseOver={(e) => {
                                            e.currentTarget.style.backgroundColor = 'var(--color-brand-blue)';
                                            e.currentTarget.style.color = 'white';
                                        }}
                                        onMouseOut={(e) => {
                                            e.currentTarget.style.backgroundColor = 'var(--color-ui-surface)';
                                            e.currentTarget.style.color = 'var(--color-brand-blue)';
                                        }}
                                    >
                                        <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
                                            {msg.action.type === 'navigate' ? 'near_me' : 'open_in_new'}
                                        </span>
                                        {msg.action.label}
                                    </button>
                                )}
                            </div>
                        ))}
                        {loading && (
                            <div style={{ alignSelf: 'flex-start', display: 'flex', gap: '4px', padding: '12px' }}>
                                <div className="dot" style={{ width: '8px', height: '8px', borderRadius: '4px', backgroundColor: 'var(--color-border-subtle)', animation: 'pulse 1s infinite 0s' }}></div>
                                <div className="dot" style={{ width: '8px', height: '8px', borderRadius: '4px', backgroundColor: 'var(--color-border-subtle)', animation: 'pulse 1s infinite 0.2s' }}></div>
                                <div className="dot" style={{ width: '8px', height: '8px', borderRadius: '4px', backgroundColor: 'var(--color-border-subtle)', animation: 'pulse 1s infinite 0.4s' }}></div>
                            </div>
                        )}
                        <style>{`
                            @keyframes pulse {
                                0%, 100% { opacity: 0.3; transform: scale(1); }
                                50% { opacity: 1; transform: scale(1.2); }
                            }
                        `}</style>
                        <div ref={messagesEndRef} />
                    </div>

                    {/* Input */}
                    <div style={{
                        padding: '16px',
                        borderTop: '1px solid var(--color-border-subtle)',
                        display: 'flex',
                        gap: '8px'
                    }}>
                        <input
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                            placeholder={t('chat.inputPlaceholder')}
                            style={{
                                flex: 1,
                                padding: '12px 16px',
                                borderRadius: '12px',
                                border: '1px solid var(--color-border-subtle)',
                                backgroundColor: 'var(--color-ui-bg)',
                                color: 'var(--color-ui-text)',
                                outline: 'none',
                                fontSize: '14px'
                            }}
                        />
                        <button
                            onClick={handleSend}
                            disabled={!input.trim() || loading}
                            style={{
                                width: '44px',
                                height: '44px',
                                borderRadius: '12px',
                                backgroundColor: 'var(--color-brand-blue)',
                                color: 'white',
                                border: 'none',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                cursor: 'pointer',
                                opacity: !input.trim() || loading ? 0.6 : 1
                            }}
                        >
                            <span className="material-symbols-outlined">send</span>
                        </button>
                    </div>
                </div>
            )}
        </>
    );
};

import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Card } from '../ui/Card';
import { useAuth } from '../../hooks/useAuth';

interface Activity {
    id: number;
    user_id: number;
    user_name: string;
    action: string;
    entity_type: string;
    entity_id: number;
    created_at: string;
    new_values: any;
}

export const ActivityFeed: FC = () => {
    const { t } = useTranslation();
    const { hasPermission, user } = useAuth();
    const [searchParams] = useSearchParams();
    const [activities, setActivities] = useState<Activity[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const isAuthorized = hasPermission('users.view');

    useEffect(() => {
        const fetchInitial = async () => {
            try {
                const token = localStorage.getItem('auth_token');
                const churchId = searchParams.get('church_id') || user?.churchId;
                const response = await fetch(`/api/activities?limit=30${churchId ? `&church_id=${churchId}` : ''}`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                const data = await response.json();
                if (data.success) {
                    setActivities(data.activities);
                    startStream(data.activities.length > 0 ? data.activities[0].id : 0);
                }
            } catch (err) {
                console.error('Error fetching activities:', err);
                setIsLoading(false);
            } finally {
                setIsLoading(false);
            }
        };

        let eventSource: EventSource | null = null;
        let retryCount = 0;

        const startStream = (lastId: number) => {
            const token = localStorage.getItem('auth_token');
            if (!token) return;

            // Close existing if any
            if (eventSource) eventSource.close();

            const churchId = searchParams.get('church_id') || user?.churchId;
            const url = `/api/activities/stream?token=${encodeURIComponent(token)}&lastId=${lastId}${churchId ? `&church_id=${churchId}` : ''}`;
            eventSource = new EventSource(url);

            eventSource.onopen = () => {
                retryCount = 0; // Reset on success
            };

            eventSource.onmessage = (event) => {
                try {
                    const newActivity = JSON.parse(event.data);
                    // Update lastId for subsequent reconnections (if the component re-renders and re-calls startStream)
                    // Note: ActivityFeed currently doesn't persist lastId in a way that handles re-renders well, 
                    // but the backend handles the stream loop.
                    setActivities(prev => {
                        if (prev.find(a => a.id === newActivity.id)) return prev;
                        return [newActivity, ...prev].slice(0, 30);
                    });
                } catch (e) {
                    // Ignore ping/malformed
                }
            };

            eventSource.onerror = (err) => {
                console.error('SSE Error, reconnecting...', err);
                eventSource?.close();

                // Exponential backoff: 3s, 6s, 12s... up to 30s
                const delay = Math.min(3000 * Math.pow(2, retryCount), 30000);
                retryCount++;

                setTimeout(() => {
                    // Use closure to get current activities if needed, 
                    // or just restart from the latest we have in state
                    startStream(activities.length > 0 ? activities[0].id : 0);
                }, delay);
            };
        };

        fetchInitial();

        return () => {
            if (eventSource) eventSource.close();
        };
    }, []);

    const getActionIcon = (action: string) => {
        if (action.startsWith('song.')) return 'library_music';
        if (action.startsWith('user.')) return 'person';
        if (action.startsWith('team.') || action.startsWith('group.')) return 'groups';
        if (action.startsWith('meeting.')) return 'calendar_month';
        if (action.startsWith('playlist.')) return 'queue_music';
        return 'history';
    };

    const formatAction = (activity: Activity) => {
        const { action, user_name, new_values } = activity;
        const details = typeof new_values === 'string' ? JSON.parse(new_values) : new_values;

        const key = action.replace('.', '_');
        const translationKey = `dashboard.activity.actions.${key}`;

        // Pass common parameters
        const params = {
            user: user_name || t('people.roles.member'),
            title: details?.title || '',
            name: details?.name || '',
            action: action
        };

        const result = t(translationKey, params);

        // Fallback for unknown actions
        if (result === translationKey) {
            return t('dashboard.activity.actions.unknown', params);
        }

        return result;
    };

    // Filter sensitive activities
    const visibleActivities = activities.filter(activity => {
        const sensitive = ['user.invite', 'user.delete', 'user.status_update'];
        if (sensitive.includes(activity.action)) {
            return isAuthorized;
        }
        return true;
    });

    if (isLoading && visibleActivities.length === 0) {
        return <p className="text-overline" style={{ textAlign: 'center', padding: '20px' }}>{t('dashboard.activity.loading')}</p>;
    }

    return (
        <section>
            <h3 className="text-h2" style={{ marginBottom: '16px' }}>{t('dashboard.activity.title')}</h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {visibleActivities.map(activity => (
                    <Card key={activity.id} style={{ padding: '12px 16px', display: 'flex', gap: '12px', alignItems: 'center' }}>
                        <div style={{
                            width: '40px',
                            height: '40px',
                            borderRadius: '10px',
                            backgroundColor: 'var(--color-ui-surface)',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            color: 'var(--color-brand-blue)'
                        }}>
                            <span className="material-symbols-outlined">{getActionIcon(activity.action)}</span>
                        </div>
                        <div style={{ flex: 1 }}>
                            <p className="text-body" style={{ fontWeight: 500, margin: 0 }}>{formatAction(activity)}</p>
                            <p className="text-overline" style={{ color: 'gray', marginTop: '2px' }}>
                                {new Date(activity.created_at).toLocaleString()}
                            </p>
                        </div>
                    </Card>
                ))}
                {visibleActivities.length === 0 && (
                    <p className="text-body" style={{ textAlign: 'center', color: 'gray', padding: '12px' }}>
                        {t('dashboard.activity.empty')}
                    </p>
                )}
            </div>
        </section>
    );
};

import { type FC } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../../hooks/useAuth';

export const DesktopSidebar: FC = () => {
    const { t } = useTranslation();
    const navigate = useNavigate();
    const location = useLocation();
    const { hasPermission } = useAuth();

    const menuItems = [
        { path: '/dashboard', icon: 'dashboard', label: t('nav.home'), permission: null },
        { path: '/mainhub/churches', icon: 'church', label: t('nav.churches'), permission: 'churches.view' },
        { path: '/mainhub/reports', icon: 'auto_graph', label: 'Estad├¡sticas', permission: 'church.update' },
        { path: '/worship/calendar', icon: 'event', label: t('nav.calendar'), permission: 'reunions.view' },
        { path: '/mainhub/areas', icon: 'layers', label: t('nav.areas'), permission: 'area.create' },
        { path: '/mainhub/teams', icon: 'groups', label: t('nav.teams'), permission: 'teams.view' },
        { path: '/mainhub/people', icon: 'person_search', label: t('nav.people'), permission: 'users.view' },
        { path: '/worship/songs', icon: 'music_note', label: t('nav.songs'), permission: 'songs.view' },
    ];

    const bottomItems = [
        { path: '/settings', icon: 'settings', label: t('nav.settings') || 'Panel de Control' }
    ];

    const visibleItems = menuItems.filter(item => !item.permission || (item.permission === 'church.update' ? hasPermission('church.update') : hasPermission(item.permission)));

    return (
        <aside style={{
            width: 'var(--sidebar-width)',
            height: '100vh',
            position: 'fixed',
            left: 0,
            top: 0,
            backgroundColor: 'var(--color-sidebar-bg)',
            borderRight: '1px solid var(--color-border-subtle)',
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'space-between',
            paddingBottom: '20px',
            zIndex: 1000
        }} className="desktop-only">
            <div>
                <div style={{ padding: '24px', display: 'flex', alignItems: 'center', gap: '12px', cursor: 'pointer' }} onClick={() => navigate('/')}>
                    <img src="/favicon.png" alt="Logo" style={{ width: '32px', height: '32px' }} />
                    <span style={{ fontWeight: 800, fontSize: '18px', color: 'var(--color-brand-blue)' }}>Church Center</span>
                </div>

                <nav style={{ padding: '12px', overflowY: 'auto' }}>
                    {visibleItems.map(item => {
                        const isActive = location.pathname === item.path || (item.path !== '/dashboard' && location.pathname.startsWith(item.path));
                        return (
                            <div
                                key={item.path}
                                onClick={() => navigate(item.path)}
                                style={{
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '12px',
                                    padding: '10px 16px',
                                    borderRadius: '12px',
                                    cursor: 'pointer',
                                    marginBottom: '4px',
                                    backgroundColor: isActive ? 'rgba(63, 108, 222, 0.1)' : 'transparent',
                                    color: isActive ? 'var(--color-brand-blue)' : 'var(--color-ui-text-soft)',
                                    transition: 'all 0.2s'
                                }}
                                className="sidebar-item"
                            >
                                <span className="material-symbols-outlined" style={{ fontSize: '22px', fontVariationSettings: isActive ? "'FILL' 1" : "'FILL' 0" }}>{item.icon}</span>
                                <span style={{ fontWeight: isActive ? 600 : 500, fontSize: '14px' }}>{item.label}</span>
                            </div>
                        );
                    })}
                </nav>
            </div>

            <div style={{ padding: '12px', borderTop: '1px solid var(--color-border-subtle)', marginTop: 'auto' }}>
                {bottomItems.map(item => (
                    <div
                        key={item.path}
                        onClick={() => navigate(item.path)}
                        style={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: '12px',
                            padding: '10px 16px',
                            borderRadius: '12px',
                            cursor: 'pointer',
                            marginBottom: '4px',
                            color: 'var(--color-ui-text-soft)',
                            transition: 'all 0.2s'
                        }}
                        className="sidebar-item"
                    >
                        <span className="material-symbols-outlined" style={{ fontSize: '22px' }}>{item.icon}</span>
                        <span style={{ fontWeight: 500, fontSize: '14px' }}>{item.label}</span>
                    </div>
                ))}
                <div
                    onClick={() => { useAuth().logout(); navigate('/login'); }}
                    style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: '12px',
                        padding: '10px 16px',
                        borderRadius: '12px',
                        cursor: 'pointer',
                        color: 'var(--color-danger-red)',
                        transition: 'all 0.2s',
                        opacity: 0.8
                    }}
                    className="sidebar-item"
                >
                    <span className="material-symbols-outlined" style={{ fontSize: '22px' }}>logout</span>
                    <span style={{ fontWeight: 500, fontSize: '14px' }}>Cerrar Sesi├│n</span>
                </div>
            </div>
        </aside>
    );
};

import type { FC } from 'react';
import { ChordProParser, HtmlDivFormatter } from 'chordsheetjs';
import { musicUtils } from '../../utils/musicUtils';

export type ChordViewMode = 'american' | 'spanish' | 'roman' | 'lyrics';

interface ChordSheetRendererProps {
    content: string;
    transpose: number;
    viewMode: ChordViewMode;
    songKey: string;
    fontSize?: number;
}

export const ChordSheetRenderer: FC<ChordSheetRendererProps> = ({
    content,
    transpose,
    viewMode,
    songKey,
    fontSize = 16
}) => {
    // 1. Parse explicitly as ChordPro
    const parser = new ChordProParser();
    const song = parser.parse(content);

    // 2. Calculate Current Key
    const currentKey = musicUtils.transposeNote(songKey, transpose);

    // 3. Transform Chords in the song object tree
    song.lines.forEach(line => {
        line.items.forEach(item => {
            // Use property check instead of instanceof for better resilience with different versions/bundling
            if (typeof item === 'object' && item !== null && 'chords' in item && item.chords) {
                const chordItem = item as any;
                // Determine transposed chord first
                let processedChord = musicUtils.transposeNote(chordItem.chords, transpose, currentKey);

                // Apply view mode transformation
                if (viewMode === 'roman') {
                    processedChord = musicUtils.toRoman(processedChord, currentKey);
                } else if (viewMode === 'spanish') {
                    processedChord = musicUtils.toSolfege(processedChord);
                }

                // Update the chord in the object
                chordItem.chords = processedChord;
            }
        });
    });

    // 4. Format to HTML
    const formatter = new HtmlDivFormatter();
    const html = formatter.format(song);

    // 5. CSS for hiding chords and styling
    const styles = `
        .chord-sheet-container {
            font-family: 'Roboto Mono', monospace;
            font-size: ${fontSize}px;
            line-height: normal;
            color: var(--color-ui-text);
        }
        .chord-sheet-container .paragraph {
            margin-bottom: 32px;
        }
        .chord-sheet-container .row {
            display: flex;
            flex-wrap: wrap;
            margin-bottom: 16px;
        }
        .chord-sheet-container .column {
            display: flex;
            flex-direction: column;
            margin-right: 0;
        }
        .chord-sheet-container .chord {
            color: var(--color-brand-blue);
            font-weight: bold;
            height: 1.5em;
            padding-top: 4px;
            display: ${viewMode === 'lyrics' ? 'none' : 'block'};
        }
        .chord-sheet-container .lyrics {
            min-height: 1.25em;
            white-space: pre;
        }
        .chord-sheet-container .comment {
            font-style: italic;
            color: gray;
            margin-bottom: 12px;
            display: block;
        }
    `;

    return (
        <div className="chord-sheet-container">
            <style>{styles}</style>
            <div dangerouslySetInnerHTML={{ __html: html }} />
        </div>
    );
};

