import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { Card } from '../ui/Card';
import { Button } from '../ui/Button';
import { peopleService } from '../../services/peopleService';

interface Props {
    onComplete: () => void;
    initialSelected?: number[];
}

export const InstrumentForm: FC<Props> = ({ onComplete, initialSelected = [] }) => {
    const [instruments, setInstruments] = useState<any[]>([]);
    const [selected, setSelected] = useState<number[]>(initialSelected);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        loadInstruments();
    }, []);

    const loadInstruments = async () => {
        const data = await peopleService.getInstruments();
        setInstruments(data);
        setLoading(false);
    };

    const toggleInstrument = (id: number) => {
        setSelected(prev =>
            prev.includes(id) ? prev.filter(iid => iid !== id) : [...prev, id]
        );
    };

    const handleSave = async () => {
        const success = await peopleService.saveInstruments(selected);
        if (success) {
            onComplete();
        } else {
            alert('Error al guardar instrumentos.');
        }
    };

    if (loading) return <div>Cargando instrumentos...</div>;

    // Group by category
    const categories = Array.from(new Set(instruments.map(i => i.category)));

    return (
        <Card style={{ maxWidth: '500px', width: '100%', padding: '24px' }}>
            <h2 className="text-h2" style={{ marginBottom: '8px' }}>Tus Instrumentos</h2>
            <p className="text-body" style={{ color: 'gray', marginBottom: '24px' }}>
                Indica qu├® instrumentos tocas o si eres cantante.
            </p>

            <div style={{ maxHeight: '400px', overflowY: 'auto', marginBottom: '24px', paddingRight: '10px' }}>
                {categories.map(cat => (
                    <div key={cat} style={{ marginBottom: '16px' }}>
                        <h3 className="text-overline" style={{ color: 'var(--color-primary)', marginBottom: '8px' }}>
                            {cat ? cat.toUpperCase() : 'OTROS'}
                        </h3>
                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                            {instruments.filter(i => i.category === cat).map(i => (
                                <button
                                    key={i.id}
                                    onClick={() => toggleInstrument(i.id)}
                                    style={{
                                        padding: '8px 12px',
                                        borderRadius: '20px',
                                        border: '1px solid ' + (selected.includes(i.id) ? 'var(--color-brand-blue)' : 'var(--color-border-subtle)'),
                                        backgroundColor: selected.includes(i.id) ? 'var(--color-brand-blue)' : 'transparent',
                                        color: selected.includes(i.id) ? 'white' : 'var(--color-ui-text)',
                                        cursor: 'pointer',
                                        fontSize: '13px',
                                        transition: 'all 0.2s'
                                    }}
                                >
                                    {i.name}
                                </button>
                            ))}
                        </div>
                    </div>
                ))}
            </div>

            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px' }}>
                <Button variant="ghost" label="Cancelar" onClick={onComplete} />
                <Button variant="primary" label="Guardar y Finalizar" onClick={handleSave} />
            </div>
        </Card>
    );
};

import { type FC, type MouseEvent } from 'react';
import type { User } from '../../types/domain';
import { Button } from '../ui/Button';

interface PeopleTableProps {
    users: User[];
    onEdit: (user: User) => void;
    onDelete: (user: User) => void;
    onResend: (user: User) => void;
    activeMenu: number | null;
    setActiveMenu: (id: number | null) => void;
    getStatusText: (item: any) => string;
}

export const PeopleTable: FC<PeopleTableProps> = ({
    users, onEdit, onDelete, onResend, activeMenu, setActiveMenu, getStatusText
}) => {
    return (
        <div style={{
            backgroundColor: 'var(--color-card-bg)',
            borderRadius: '16px',
            border: '1px solid var(--color-border-subtle)',
            overflow: 'visible'
        }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                <thead>
                    <tr style={{ borderBottom: '1px solid var(--color-border-subtle)', backgroundColor: 'rgba(0,0,0,0.02)' }}>
                        <th style={{ padding: '16px 24px', fontSize: '12px', fontWeight: 700, textTransform: 'uppercase', color: 'var(--color-ui-text-soft)' }}>Nombre / Rol</th>
                        <th style={{ padding: '16px 24px', fontSize: '12px', fontWeight: 700, textTransform: 'uppercase', color: 'var(--color-ui-text-soft)' }}>Contacto</th>
                        <th style={{ padding: '16px 24px', fontSize: '12px', fontWeight: 700, textTransform: 'uppercase', color: 'var(--color-ui-text-soft)' }}>Estado</th>
                        <th style={{ padding: '16px 24px', fontSize: '12px', fontWeight: 700, textTransform: 'uppercase', color: 'var(--color-ui-text-soft)' }}>├üreas</th>
                        <th style={{ padding: '16px 24px', fontSize: '12px', fontWeight: 700, textTransform: 'uppercase', color: 'var(--color-ui-text-soft)', textAlign: 'right' }}>Acciones</th>
                    </tr>
                </thead>
                <tbody>
                    {users.map(item => (
                        <tr
                            key={item.id}
                            onClick={() => onEdit(item)}
                            style={{ borderBottom: '1px solid var(--color-border-subtle)', cursor: 'pointer' }}
                            className="table-row-hover"
                        >
                            <td style={{ padding: '16px 24px' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                    <div style={{
                                        width: '40px', height: '40px', borderRadius: '12px',
                                        backgroundColor: (item.role?.name === 'pastor' || item.role?.name === 'admin' ? '#9333EA' : '#475569'),
                                        display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold'
                                    }}>
                                        {item.name.charAt(0)}
                                    </div>
                                    <div>
                                        <div style={{ fontWeight: 600, color: 'var(--color-ui-text)' }}>{item.name}</div>
                                        <div style={{ fontSize: '12px', color: 'var(--color-ui-text-soft)' }}>{item.role?.displayName || 'Miembro'}</div>
                                    </div>
                                </div>
                            </td>
                            <td style={{ padding: '16px 24px' }}>
                                <div style={{ fontSize: '14px', color: 'var(--color-ui-text)' }}>{item.email}</div>
                                {item.phone && <div style={{ fontSize: '12px', color: 'var(--color-ui-text-soft)' }}>{item.phone}</div>}
                            </td>
                            <td style={{ padding: '16px 24px' }}>
                                <span style={{
                                    fontSize: '11px', fontWeight: 700, textTransform: 'uppercase',
                                    padding: '4px 10px', borderRadius: '20px',
                                    backgroundColor: item.status === 'active' ? 'rgba(16, 185, 129, 0.1)' : 'rgba(245, 158, 11, 0.1)',
                                    color: item.status === 'active' ? '#10B981' : '#F59E0B'
                                }}>
                                    {getStatusText(item)}
                                </span>
                            </td>
                            <td style={{ padding: '16px 24px' }}>
                                <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap' }}>
                                    {item.areas?.map((a: any) => (
                                        <span key={a.id} style={{ fontSize: '10px', fontWeight: 600, padding: '2px 8px', borderRadius: '6px', border: '1px solid var(--color-border-subtle)', color: 'var(--color-ui-text-soft)' }}>
                                            {a.name}
                                        </span>
                                    ))}
                                </div>
                            </td>
                            <td style={{ padding: '16px 24px', textAlign: 'right' }}>
                                <div style={{ display: 'flex', justifyContent: 'flex-end', position: 'relative' }} className="card-menu-container" onClick={e => e.stopPropagation()}>
                                    <Button
                                        variant="ghost"
                                        icon="more_vert"
                                        onClick={(e: MouseEvent) => { e.stopPropagation(); setActiveMenu(activeMenu === item.id ? null : item.id); }}
                                        style={{ minWidth: 'auto', padding: '8px' }}
                                    />
                                    {activeMenu === item.id && (
                                        <div className="dropdown-menu" style={{ right: 0, top: '40px', width: '200px' }}>
                                            {item.status === 'pending' ? (
                                                <div onClick={() => { onResend(item); setActiveMenu(null); }} className="dropdown-item">
                                                    <span className="material-symbols-outlined">send</span> Reenviar
                                                </div>
                                            ) : (
                                                <div onClick={() => { onEdit(item); setActiveMenu(null); }} className="dropdown-item">
                                                    <span className="material-symbols-outlined">edit</span> Editar
                                                </div>
                                            )}
                                            <div onClick={() => { onDelete(item); setActiveMenu(null); }} className="dropdown-item" style={{ color: 'var(--color-danger-red)' }}>
                                                <span className="material-symbols-outlined">delete</span> Eliminar
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

import type { FC } from 'react';
import { useState } from 'react';
import { Button } from '../ui/Button';

interface AssignmentFormProps {
    instanceId: number;
    members: any[];
    instruments: any[];
    onSuccess: () => void;
    onCancel: () => void;
}

export const AssignmentForm: FC<AssignmentFormProps> = ({ instanceId, members, instruments, onSuccess, onCancel }) => {
    const [formData, setFormData] = useState({
        member_id: '',
        role: '',
        instrument_id: '',
        is_replacement: false
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);
        try {
            const token = localStorage.getItem('auth_token');
            const response = await fetch('/api/calendar.php?action=assign_team', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({
                    meeting_instance_id: instanceId,
                    ...formData
                })
            });
            const data = await response.json();
            if (data.success) {
                onSuccess();
            }
        } catch (err) {
            console.error('Error assigning member:', err);
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            <div className="input-field">
                <label className="text-overline">Miembro</label>
                <select
                    value={formData.member_id}
                    onChange={e => setFormData({ ...formData, member_id: e.target.value })}
                    required
                >
                    <option value="">Seleccionar miembro...</option>
                    {members.map(m => (
                        <option key={m.id} value={m.id}>{m.name} ({m.role_name})</option>
                    ))}
                </select>
            </div>

            <div className="input-field">
                <label className="text-overline">Rol en la reuni├│n</label>
                <input
                    type="text"
                    placeholder="Ej: Director de Alabanza"
                    value={formData.role}
                    onChange={e => setFormData({ ...formData, role: e.target.value })}
                    required
                />
            </div>

            <div className="input-field">
                <label className="text-overline">Instrumento (Opcional)</label>
                <select
                    value={formData.instrument_id}
                    onChange={e => setFormData({ ...formData, instrument_id: e.target.value })}
                >
                    <option value="">Ninguno</option>
                    {instruments.map(i => (
                        <option key={i.id} value={i.id}>{i.name}</option>
                    ))}
                </select>
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <input
                    type="checkbox"
                    id="is_replacement"
                    checked={formData.is_replacement}
                    onChange={e => setFormData({ ...formData, is_replacement: e.target.checked })}
                />
                <label htmlFor="is_replacement" className="text-body" style={{ fontSize: '14px' }}>Es un reemplazo</label>
            </div>

            <div style={{ display: 'flex', gap: '12px', marginTop: '8px' }}>
                <Button label="Cancelar" variant="secondary" onClick={onCancel} style={{ flex: 1 }} type="button" />
                <Button
                    label={isSubmitting ? "Asignando..." : "Asignar"}
                    variant="primary"
                    style={{ flex: 1 }}
                    type="submit"
                    disabled={isSubmitting}
                />
            </div>
        </form>
    );
};

import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { Button } from '../ui/Button';
import { Modal } from '../ui/Modal';
import { AssignmentForm } from './AssignmentForm';
import { SetlistAssignmentForm } from './SetlistAssignmentForm';

interface MeetingDetailViewProps {
    instanceId: number;
    onClose: () => void;
}

export const MeetingDetailView: FC<MeetingDetailViewProps> = ({ instanceId, onClose }) => {
    const [details, setDetails] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [assignmentData, setAssignmentData] = useState<any>(null);
    const [activeModal, setActiveModal] = useState<'none' | 'team' | 'setlist'>('none');

    useEffect(() => {
        fetchDetails();
        fetchAssignmentData();
    }, [instanceId]);

    const fetchAssignmentData = async () => {
        try {
            const token = localStorage.getItem('auth_token');
            const response = await fetch(`/api/calendar/assignment-data`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await response.json();
            if (data.success) {
                setAssignmentData(data);
            }
        } catch (err) {
            console.error('Error fetching assignment data:', err);
        }
    };

    const fetchDetails = async () => {
        setIsLoading(true);
        try {
            const token = localStorage.getItem('auth_token');
            const response = await fetch(`/api/calendar/events/${instanceId}`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await response.json();
            if (data.success) {
                setDetails(data.details);
            }
        } catch (err) {
            console.error('Error fetching details:', err);
        } finally {
            setIsLoading(false);
        }
    };

    if (isLoading) return <div className="flex-center" style={{ height: '200px' }}><div className="spinner" /></div>;
    if (!details) return <p>No se encontraron detalles.</p>;

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            <section>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                        <p className="text-overline" style={{ color: 'var(--color-brand-blue)' }}>
                            {new Date(details.instance_date).toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
                        </p>
                        <h2 className="text-h2" style={{ margin: '4px 0' }}>{details.title}</h2>
                        <p className="text-body" style={{ color: '#6B7280' }}>
                            {new Date(details.start_datetime_utc).toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' })}
                            {' - '}
                            {new Date(details.end_datetime_utc).toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' })}
                        </p>
                    </div>
                </div>
                {details.description && (
                    <p className="text-body" style={{ marginTop: '16px', fontSize: '14px', fontStyle: 'italic' }}>
                        {details.description}
                    </p>
                )}
            </section>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '24px' }}>
                <section>
                    <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                        <h4 className="text-overline">EQUIPO ASIGNADO</h4>
                        <Button variant="ghost" icon="person_add" style={{ padding: '4px' }} onClick={() => setActiveModal('team')} />
                    </header>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        {details.team.length > 0 ? details.team.map((member: any) => (
                            <div key={member.id} style={{
