import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Card } from '../../../../components/ui/Card';
import { Button } from '../../../../components/ui/Button';
import { useAuth } from '../../../../hooks/useAuth';

export const AreaList: FC = () => {
    const { t } = useTranslation();
    const { isMaster } = useAuth();
    const [areas, setAreas] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [editingArea, setEditingArea] = useState<any>(null);
    const [newName, setNewName] = useState('');
    const [showNewForm, setShowNewForm] = useState(false);
    const [selectedChurchId, setSelectedChurchId] = useState<string>('');
    const [churches, setChurches] = useState<any[]>([]);

    useEffect(() => {
        fetchChurches();
        fetchAreas();
    }, [selectedChurchId]);

    const fetchChurches = async () => {
        if (!isMaster) return;
        try {
            const token = localStorage.getItem('auth_token');
            const response = await fetch('/api/churches', {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const result = await response.json();
            if (result.success) setChurches(result.churches || []);
        } catch (err) {
            console.error('Error fetching churches:', err);
        }
    };

    const fetchAreas = async () => {
        setIsLoading(true);
        try {
            const token = localStorage.getItem('auth_token');
            const url = selectedChurchId ? `/api/areas?church_id=${selectedChurchId}` : '/api/areas';
            const response = await fetch(url, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const result = await response.json();
            if (result.success) {
                setAreas(result.areas || []);
            }
        } catch (err) {
            console.error('Error fetching areas:', err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newName || (!selectedChurchId && !editingArea)) return;

        try {
            const token = localStorage.getItem('auth_token');
            const url = editingArea ? `/api/areas/${editingArea.id}` : `/api/areas?church_id=${selectedChurchId}`;
            const method = editingArea ? 'PUT' : 'POST';

            const response = await fetch(url, {
                method,
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify({ name: newName })
            });

            const result = await response.json();
            if (result.success) {
                setNewName('');
                setEditingArea(null);
                setShowNewForm(false);
                fetchAreas();
            }
        } catch (err) {
            console.error('Error saving area:', err);
        }
    };

    const handleDelete = async (id: number) => {
        if (!window.confirm(t('common.confirmDelete') || '┬┐Est├ís seguro?')) return;
        try {
            const token = localStorage.getItem('auth_token');
            const response = await fetch(`/api/areas/${id}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const result = await response.json();
            if (result.success) fetchAreas();
        } catch (err) {
            console.error('Error deleting area:', err);
        }
    };

    const getAreaIcon = (name: string) => {
        const n = name.toLowerCase();
        if (n.includes('alabanza') || n.includes('musica') || n.includes('m├║sica')) return 'music_note';
        if (n.includes('sonido') || n.includes('audio') || n.includes('tecnica')) return 'surround_sound';
        if (n.includes('ujier') || n.includes('acogida') || n.includes('orden')) return 'hail';
        if (n.includes('multimedia') || n.includes('video') || n.includes('proyeccion')) return 'videocam';
        if (n.includes('ni├▒o') || n.includes('escuela') || n.includes('infantil')) return 'child_care';
        if (n.includes('joven') || n.includes('adolescente')) return 'groups_3';
        if (n.includes('intercesion') || n.includes('oracion')) return 'volunteer_activism';
        if (n.includes('limpieza') || n.includes('mantenimiento')) return 'cleaning_services';
        if (n.includes('pastoral') || n.includes('conseje')) return 'church';
        return 'layers';
    };

    return (
        <div>
            <header style={{ marginBottom: '24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                    <h1 className="text-h1">{t('nav.areas')}</h1>
                    <p className="text-body" style={{ color: 'gray' }}>Gesti├│n independiente de ├íreas y departamentos.</p>
                </div>
                <Button
                    variant="primary"
                    icon="add"
                    label={t('common.add') || 'A├▒adir'}
                    onClick={() => {
                        setEditingArea(null);
                        setNewName('');
                        setShowNewForm(true);
                    }}
                />
            </header>

            {isMaster && (
                <div style={{ marginBottom: '20px' }}>
                    <label className="text-overline" style={{ display: 'block', marginBottom: '8px' }}>Filtrar por Iglesia</label>
                    <select
                        value={selectedChurchId}
                        onChange={e => setSelectedChurchId(e.target.value)}
                        className="w-full"
                        style={{ padding: '10px', borderRadius: '12px', border: '1px solid var(--color-border-subtle)' }}
                    >
                        <option value="">Todas las iglesias</option>
                        {churches.map(c => (
                            <option key={c.id} value={c.id}>{c.name}</option>
                        ))}
                    </select>
                </div>
            )}

            {(showNewForm || editingArea) && (
                <Card style={{ padding: '20px', marginBottom: '24px' }}>
                    <form onSubmit={handleSave} style={{ display: 'flex', gap: '12px', alignItems: 'flex-end' }}>
                        <div style={{ flex: 1 }}>
                            <label className="text-overline" style={{ display: 'block', marginBottom: '8px' }}>
                                {editingArea ? 'Editar ├ürea' : 'Nueva ├ürea'}
                            </label>
                            <input
                                type="text"
                                value={newName}
                                onChange={e => setNewName(e.target.value)}
                                placeholder="Nombre del ├írea (ej. Alabanza)"
                                required
                                className="w-full"
                            />
                        </div>
                        <Button type="button" variant="secondary" label={t('common.cancel')} onClick={() => { setShowNewForm(false); setEditingArea(null); }} />
                        <Button type="submit" variant="primary" label={t('common.save')} />
                    </form>
                </Card>
            )}

            <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
                gap: '16px'
            }}>
                {isLoading ? (
                    <div className="flex-center" style={{ height: '100px', gridColumn: '1 / -1' }}><div className="spinner" /></div>
                ) : areas.length === 0 ? (
                    <p style={{ textAlign: 'center', color: 'gray', padding: '40px', gridColumn: '1 / -1' }}>No hay ├íreas registradas.</p>
                ) : (
                    areas.map(area => (
                        <Card key={area.id} style={{
                            display: 'flex',
                            justifyContent: 'space-between',
                            alignItems: 'center',
                            padding: '16px 20px',
                            transition: 'all 0.2s',
                            cursor: 'default',
                            position: 'relative'
                        }} className="sidebar-item">
                            <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                                <div style={{
                                    width: '40px',
                                    height: '40px',
                                    borderRadius: '10px',
                                    backgroundColor: 'rgba(59, 130, 246, 0.1)',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    color: 'var(--color-brand-blue)',
                                }}>
                                    <span className="material-symbols-outlined" style={{ fontSize: '24px' }}>{getAreaIcon(area.name)}</span>
                                </div>
                                <div>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                        <h3 className="text-card-title" style={{ fontSize: '16px', fontWeight: 600 }}>{area.name}</h3>
                                        {/* Teams Count Badge */}
                                        <div style={{
                                            display: 'flex',
                                            alignItems: 'center',
                                            gap: '4px',
                                            padding: '2px 8px',
                                            borderRadius: '12px',
                                            backgroundColor: 'var(--color-ui-surface)',
                                            color: 'var(--color-ui-text-soft)',
                                            fontSize: '11px',
                                            fontWeight: 700
                                        }}>
                                            <span className="material-symbols-outlined" style={{ fontSize: '14px' }}>groups</span>
                                            <span>{area.teams_count || 0}</span>
                                        </div>
                                    </div>
                                    {area.church_name && <p className="text-overline" style={{ color: 'var(--color-brand-blue)', fontWeight: 600, fontSize: '11px', marginTop: '2px' }}>{area.church_name}</p>}
                                </div>
                            </div>
                            <div style={{ display: 'flex', gap: '8px' }}>
                                <Button
                                    variant="ghost"
                                    icon="edit"
                                    onClick={() => { setEditingArea(area); setNewName(area.name); }}
                                    style={{ padding: '8px', minWidth: 'auto', color: 'var(--color-ui-text-soft)' }}
                                />
                                <Button
                                    variant="ghost"
                                    icon="delete"
                                    onClick={() => handleDelete(area.id)}
                                    style={{ padding: '8px', minWidth: 'auto', color: 'var(--color-danger-red)' }}
                                />
                            </div>
                        </Card>
                    ))
                )}
            </div>

        </div>
    );
};

import type { FC } from 'react';
import { useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Card } from '../../../../components/ui/Card';
import { Button } from '../../../../components/ui/Button';

export const AreaSetup: FC = () => {
    const { t } = useTranslation();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const churchId = searchParams.get('church_id');
    const [areas, setAreas] = useState<string[]>(['Ujieres', 'Alabanza']);
    const [isSaving, setIsSaving] = useState(false);
    const [error, setError] = useState('');

    const handleAddArea = () => setAreas([...areas, '']);

    const handleRemoveArea = (index: number) => {
        if (areas.length > 1) {
            setAreas(areas.filter((_, i) => i !== index));
        }
    };

    const handleAreaChange = (index: number, value: string) => {
        const newAreas = [...areas];
        newAreas[index] = value;
        setAreas(newAreas);
    };

    const handleContinue = async () => {
        const validAreas = areas.filter(a => a.trim().length > 0);
        if (validAreas.length === 0) {
            setError(t('setup.areas.errorEmpty'));
            return;
        }

        setIsSaving(true);
        setError('');

        try {
            const token = localStorage.getItem('auth_token');
            for (const areaName of validAreas) {
                const response = await fetch(`/api/areas${churchId ? `?church_id=${churchId}` : ''}`, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${token}`
                    },
                    body: JSON.stringify({ name: areaName })
                });

                const result = await response.json();
                if (!result.success) {
                    throw new Error(result.message);
                }
            }
            navigate(`/mainhub/setup-teams${churchId ? `?church_id=${churchId}` : ''}`);
        } catch (err: any) {
            setError(err.message || t('setup.areas.errorDelay'));
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <div style={{ maxWidth: '600px', margin: '0 auto', paddingBottom: '40px' }}>
            <header style={{ marginBottom: '24px' }}>
                <h1 className="text-h1">{t('setup.areas.title')}</h1>
                <p className="text-body" style={{ color: 'gray' }}>{t('setup.areas.subtitle')}</p>
            </header>

            <Card style={{ padding: '24px', display: 'flex', flexDirection: 'column', gap: '20px' }}>
                {error && (
                    <div style={{
                        padding: '12px', backgroundColor: 'rgba(239, 68, 68, 0.1)', color: '#EF4444',
                        borderRadius: '8px', fontSize: '14px', border: '1px solid rgba(239, 68, 68, 0.2)'
                    }}>
                        {error}
                    </div>
                )}

                <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                    {areas.map((area, index) => (
                        <div key={index} style={{ display: 'flex', gap: '8px' }}>
                            <input
                                type="text"
                                placeholder={t('setup.areas.placeholder')}
                                value={area}
                                onChange={e => handleAreaChange(index, e.target.value)}
                                style={{
                                    flex: 1, padding: '12px', borderRadius: '12px',
                                    border: '1px solid var(--color-border-subtle)',
                                    backgroundColor: 'var(--color-ui-bg)', color: 'var(--color-ui-text)',
                                    outline: 'none', fontSize: '16px'
                                }}
                            />
                            {areas.length > 1 && (
                                <Button variant="secondary" onClick={() => handleRemoveArea(index)} style={{ padding: '8px' }}>
                                    <span className="material-symbols-outlined">delete</span>
                                </Button>
                            )}
                        </div>
                    ))}
                </div>

                <Button variant="ghost" icon="add" label={t('setup.areas.addAction')} onClick={handleAddArea} />

                <div style={{ marginTop: '12px' }}>
                    <Button
                        variant="primary"
                        onClick={handleContinue}
                        disabled={isSaving}
                        style={{ width: '100%', height: '48px' }}
                    >
                        {isSaving ? t('setup.areas.saving') : t('setup.areas.continue')}
                    </Button>
                </div>
            </Card>
        </div>
    );
};

import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Card } from '../../../../components/ui/Card';
import { Button } from '../../../../components/ui/Button';
import { useToast } from '../../../../context/ToastContext';

export const ChurchEditor: FC = () => {
    const { t } = useTranslation();
    const navigate = useNavigate();
    const { id } = useParams();
    const { addToast } = useToast();
    const [formData, setFormData] = useState({
        name: '',
        slug: '',
        address: '',
        timezone: 'America/Argentina/Buenos_Aires'
    });
    const [isSaving, setIsSaving] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        if (id) {
            fetchChurch();
        }
    }, [id]);

    const fetchChurch = async () => {
        setIsLoading(true);
        try {
            const token = localStorage.getItem('auth_token');
            const response = await fetch(`/api/churches/${id}`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const result = await response.json();
            if (result.success) {
                setFormData({
                    name: result.church.name,
                    slug: result.church.slug,
                    address: result.church.address || '',
                    timezone: result.church.timezone || 'America/Argentina/Buenos_Aires'
                });
            } else {
                setError(result.error || 'Error al cargar iglesia');
            }
        } catch (err) {
            setError('Error de conexi├│n');
        } finally {
            setIsLoading(false);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        setError('');

        try {
            const token = localStorage.getItem('auth_token');
            const url = id ? `/api/churches/${id}` : '/api/churches';
            const method = id ? 'PUT' : 'POST';

            const response = await fetch(url, {
                method,
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify(formData)
            });

            const result = await response.json();
            if (result.success) {
                if (id) {
                    addToast(t('churches.updateSuccess') || 'Iglesia actualizada correctamente', 'success');
                    navigate('/mainhub/churches');
                } else {
                    // Redirect to Step 2: Area Setup
                    navigate(`/mainhub/setup-areas?church_id=${result.id}`);
                }
            } else {
                setError(result.error || (id ? 'Error al actualizar' : t('setup.church.errorCreate')));
            }
        } catch (err) {
            setError(t('setup.church.errorConnection'));
        } finally {
            setIsSaving(false);
        }
    };

    const generateSlug = (name: string) => {
        return name.toLowerCase()
            .trim()
            .replace(/[^\w\s-]/g, '')
            .replace(/[\s_-]+/g, '-')
            .replace(/^-+|-+$/g, '');
    };

    const handleNameChange = (name: string) => {
        setFormData(prev => ({
            ...prev,
            name,
            slug: generateSlug(name)
        }));
    };

    return (
        <div style={{ maxWidth: '600px', margin: '0 auto', paddingBottom: '40px' }}>
            <header style={{ marginBottom: '24px', display: 'flex', alignItems: 'center', gap: '12px' }}>
                <Button variant="secondary" onClick={() => navigate('/mainhub/churches')} style={{ padding: '8px' }}>
                    <span className="material-symbols-outlined">arrow_back</span>
                </Button>
                <h1 className="text-h1">{id ? 'Editar Iglesia' : t('setup.church.title')}</h1>
            </header>

            {isLoading ? (
                <Card style={{ padding: '40px', textAlign: 'center' }}>
                    <div className="spinner" style={{ margin: '0 auto' }} />
                </Card>
            ) : (
                <form onSubmit={handleSave}>
                    <Card style={{ padding: '24px', display: 'flex', flexDirection: 'column', gap: '20px' }}>
                        {error && (
                            <div style={{
                                padding: '12px',
                                backgroundColor: 'rgba(239, 68, 68, 0.1)',
                                color: '#EF4444',
                                borderRadius: '8px',
                                fontSize: '14px',
                                border: '1px solid rgba(239, 68, 68, 0.2)'
                            }}>
                                {error}
                            </div>
                        )}

                        <div>
                            <label className="text-overline" style={{ display: 'block', marginBottom: '8px', color: 'gray' }}>
                                {t('setup.church.nameLabel')}
                            </label>
                            <input
                                type="text"
                                required
                                placeholder={t('setup.church.namePlaceholder')}
                                value={formData.name}
                                onChange={e => handleNameChange(e.target.value)}
                                style={{
                                    width: '100%',
                                    padding: '12px',
                                    borderRadius: '12px',
                                    border: '1px solid var(--color-border-subtle)',
                                    backgroundColor: 'var(--color-ui-bg)',
                                    color: 'var(--color-ui-text)',
                                    outline: 'none',
                                    fontSize: '16px'
                                }}
                            />
                        </div>

                        <div>
                            <label className="text-overline" style={{ display: 'block', marginBottom: '8px', color: 'gray' }}>
                                {t('setup.church.slugLabel')}
                            </label>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                                <span className="text-body" style={{ color: 'gray' }}>msm.com/</span>
                                <input
                                    type="text"
                                    required
                                    placeholder="cita-central"
                                    value={formData.slug}
                                    onChange={e => setFormData({ ...formData, slug: generateSlug(e.target.value) })}
                                    style={{
                                        flex: 1,
                                        padding: '12px',
                                        borderRadius: '12px',
                                        border: '1px solid var(--color-border-subtle)',
                                        backgroundColor: 'var(--color-ui-bg)',
                                        color: 'var(--color-ui-text)',
                                        outline: 'none',
                                        fontSize: '14px',
                                        fontFamily: 'monospace'
                                    }}
                                />
                            </div>
                            <p className="text-overline" style={{ marginTop: '4px', color: '#6B7280', fontSize: '10px' }}>
                                {t('setup.church.slugHint')}
                            </p>
                        </div>

                        <div>
                            <label className="text-overline" style={{ display: 'block', marginBottom: '8px', color: 'gray' }}>
                                {t('setup.church.addressLabel')}
                            </label>
                            <textarea
                                placeholder={t('setup.church.addressPlaceholder')}
                                value={formData.address}
                                onChange={e => setFormData({ ...formData, address: e.target.value })}
                                style={{
                                    width: '100%',
                                    padding: '12px',
                                    borderRadius: '12px',
                                    border: '1px solid var(--color-border-subtle)',
                                    backgroundColor: 'var(--color-ui-bg)',
                                    color: 'var(--color-ui-text)',
                                    outline: 'none',
                                    fontSize: '14px',
                                    minHeight: '80px',
                                    resize: 'vertical'
                                }}
                            />
                        </div>

                        <div style={{ marginTop: '12px' }}>
                            <Button
                                variant="primary"
                                type="submit"
                                disabled={isSaving}
                                style={{ width: '100%', height: '48px' }}
                            >
                                {isSaving ? t('setup.church.saving') : t('setup.church.submit')}
                            </Button>
                        </div>
                    </Card>
                </form>
            )}

            {!id && (
                <section style={{ marginTop: '24px' }}>
                    <p className="text-overline" style={{ textAlign: 'center', color: '#6B7280' }}>
                        {t('setup.church.notice')}
                    </p>
                </section>
            )}
        </div>
    );
};

import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Card } from '../../../../components/ui/Card';
import { Button } from '../../../../components/ui/Button';
import { useAuth } from '../../../../hooks/useAuth';
import { useToast } from '../../../../context/ToastContext';

export const ChurchList: FC = () => {
    const { t } = useTranslation();
    const navigate = useNavigate();
    const { isMaster } = useAuth();
    const { addToast } = useToast();
    const [churches, setChurches] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showFilters, setShowFilters] = useState(false);

    const [viewMode, setViewMode] = useState<'list' | 'grid'>('list');

    useEffect(() => {
        fetchChurches();
    }, []);

    const fetchChurches = async () => {
        try {
            const token = localStorage.getItem('auth_token');
            const response = await fetch('/api/churches', {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const result = await response.json();
            if (result.success) {
                setChurches(result.churches || []);
            }
        } catch (err) {
            console.error('Error fetching churches:', err);
        } finally {
            setIsLoading(false);
        }
    };

    const filteredChurches = churches.filter(c =>
        c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        c.slug.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const handleAction = async (church: any, action: 'deactivate' | 'restore' | 'hardDelete') => {
        let confirmMsg = '';
        if (action === 'deactivate') {
            confirmMsg = t('churches.confirmDeactivate', { name: church.name });
        } else if (action === 'hardDelete') {
            confirmMsg = t('churches.confirmHardDelete', { name: church.name });
        } else if (action === 'restore') {
            confirmMsg = t('churches.confirmRestore', { name: church.name }) || `┬┐Deseas reactivar la iglesia ${church.name}?`;
        }

        if (!window.confirm(confirmMsg)) {
            return;
        }

        try {
            const token = localStorage.getItem('auth_token');
            const url = action === 'restore' ? '/api/churches/restore' : `/api/churches/${church.id}`;
            const method = action === 'restore' ? 'POST' : 'DELETE';
            const body = action === 'restore' ? JSON.stringify({ id: church.id }) : undefined;

            const response = await fetch(url, {
                method,
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body
            });

            const result = await response.json();
            if (result.success) {
                addToast(result.message || t('common.success'), 'success');
                fetchChurches();
            } else {
                addToast(result.error || t('common.error'), 'error');
            }
        } catch (err) {
            console.error('Church action error:', err);
            addToast(t('common.error_unexpected'), 'error');
        }
    };

    return (
        <div>
            <header style={{ marginBottom: '24px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                    <h1 className="text-h1">{t('churches.title')}</h1>
                    <div style={{ display: 'flex', gap: '8px' }}>
                        <div style={{ display: 'flex', backgroundColor: 'var(--color-ui-surface)', borderRadius: '10px', padding: '4px', gap: '4px' }}>
                            <Button
                                variant={viewMode === 'list' ? 'primary' : 'ghost'}
                                icon="format_list_bulleted"
                                onClick={() => setViewMode('list')}
                                style={{ padding: '6px', minWidth: 'auto' }}
                            />
                            <Button
                                variant={viewMode === 'grid' ? 'primary' : 'ghost'}
                                icon="grid_view"
                                onClick={() => setViewMode('grid')}
                                style={{ padding: '6px', minWidth: 'auto' }}
                            />
                        </div>
                        <Button
                            variant="primary"
                            icon="add"
                            label={t('churches.new')}
                            onClick={() => navigate('/mainhub/churches/new')}
                        />
                    </div>
                </div>

                <div style={{ position: 'relative', display: 'flex', gap: '8px' }}>
                    <div style={{ position: 'relative', flex: 1 }}>
                        <span className="material-symbols-outlined" style={{
                            position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'gray'
                        }}>search</span>
                        <input
                            type="text"
                            placeholder={t('churches.search')}
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                            style={{
                                width: '100%',
                                padding: '12px 12px 12px 40px',
                                borderRadius: '12px',
                                border: '1px solid var(--color-border-subtle)',
                                backgroundColor: 'var(--color-ui-bg)',
                                color: 'var(--color-ui-text)',
                                outline: 'none',
                                fontSize: '14px'
                            }}
                        />
                    </div>
                    <Button
                        variant="secondary"
                        onClick={() => setShowFilters(!showFilters)}
                        style={{ padding: '0 12px' }}
                    >
                        <span className="material-symbols-outlined">filter_list</span>
                    </Button>
                </div>

                {showFilters && (
                    <Card style={{ padding: '16px', marginTop: '12px' }}>
                        <p className="text-overline" style={{ color: 'gray' }}>{t('churches.filters.upcoming')}</p>
                    </Card>
                )}
            </header>

            <div style={viewMode === 'grid' ? {
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
                gap: '20px'
            } : {
                display: 'flex',
                flexDirection: 'column',
                gap: '12px'
            }}>
                {isLoading ? (
                    <div className="flex-center" style={{ height: '200px', gridColumn: '1 / -1' }}>
                        <div className="spinner" />
                    </div>
                ) : filteredChurches.length === 0 ? (
                    <p className="text-body" style={{ textAlign: 'center', color: 'gray', marginTop: '40px', gridColumn: '1 / -1' }}>{t('churches.noResults')}</p>
                ) : (
                    filteredChurches.map(church => (
                        <Card
                            key={church.id}
                            style={{
                                display: 'flex',
                                flexDirection: viewMode === 'grid' ? 'column' : 'row',
                                justifyContent: 'space-between',
                                alignItems: viewMode === 'grid' ? 'flex-start' : 'center',
                                padding: '20px',
                                opacity: church.is_active ? 1 : 0.6,
                                filter: church.is_active ? 'none' : 'grayscale(0.5)',
                                cursor: 'pointer',
                                transition: 'all 0.2s',
                                minHeight: viewMode === 'grid' ? '180px' : 'auto',
                                position: 'relative'
                            }}
                            className="sidebar-item"
                            onClick={() => navigate(`/mainhub/churches/edit/${church.id}`)}
                        >
                            <div style={{
                                display: 'flex',
                                flexDirection: viewMode === 'grid' ? 'column' : 'row',
                                alignItems: viewMode === 'grid' ? 'flex-start' : 'center',
                                gap: viewMode === 'grid' ? '16px' : '20px',
                                flex: 1,
                                minWidth: 0,
                                width: '100%'
                            }}>
                                <div style={{
                                    width: '48px',
                                    height: '48px',
                                    borderRadius: '12px',
                                    backgroundColor: 'rgba(59, 130, 246, 0.1)',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    color: 'var(--color-brand-blue)',
                                    border: '1px solid rgba(59, 130, 246, 0.1)',
                                    flexShrink: 0
                                }}>
                                    <span className="material-symbols-outlined" style={{ fontSize: '28px' }}>church</span>
                                </div>
                                <div style={{ display: 'flex', flexDirection: 'column', flex: 1, minWidth: 0, width: '100%' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
                                        <h3 className="text-card-title" style={{
                                            fontSize: '16px',
                                            fontWeight: 700,
                                            margin: 0,
                                            wordBreak: 'break-word',
                                            lineHeight: 1.2
                                        }}>
                                            {church.name}
                                        </h3>
                                        {!church.is_active && (
                                            <span style={{
                                                fontSize: '9px',
                                                padding: '2px 6px',
                                                borderRadius: '4px',
                                                backgroundColor: 'rgba(239, 68, 68, 0.1)',
                                                color: '#EF4444',
                                                fontWeight: 700,
                                                textTransform: 'uppercase'
                                            }}>
                                                {t('churches.status.inactive') || 'Desactivada'}
                                            </span>
                                        )}
                                    </div>
                                    <p className="text-overline" style={{ color: 'var(--color-brand-blue)', fontWeight: 600, fontSize: '11px', marginTop: '4px' }}>/{church.slug}</p>
                                </div>
                            </div>

                            <div style={{
                                display: 'flex',
                                gap: '8px',
                                alignItems: 'center',
                                marginTop: viewMode === 'grid' ? '16px' : 0,
                                justifyContent: viewMode === 'grid' ? 'flex-end' : 'flex-start',
                                width: viewMode === 'grid' ? '100%' : 'auto'
                            }} onClick={e => e.stopPropagation()}>
                                {isMaster && (
                                    <div style={{ display: 'flex', gap: '4px' }}>
                                        <Button
                                            variant="ghost"
                                            icon="edit"
                                            onClick={() => navigate(`/mainhub/churches/edit/${church.id}`)}
                                            style={{ padding: '8px', minWidth: 'auto', color: 'var(--color-ui-text-soft)' }}
                                        />
                                        {church.is_active ? (
                                            <Button
                                                variant="ghost"
                                                icon="block"
                                                onClick={() => handleAction(church, 'deactivate')}
                                                style={{ padding: '8px', minWidth: 'auto', color: '#F59E0B' }}
                                                title={t('churches.deactivate')}
                                            />
                                        ) : (
                                            <Button
                                                variant="ghost"
                                                icon="settings_backup_restore"
                                                onClick={() => handleAction(church, 'restore')}
                                                style={{ padding: '8px', minWidth: 'auto', color: '#10B981' }}
                                                title={t('churches.restore')}
                                            />
                                        )}
                                    </div>
                                )}
                                {viewMode === 'list' && <span className="material-symbols-outlined" style={{ color: 'var(--color-ui-text-soft)', fontSize: '20px' }}>chevron_right</span>}
                            </div>
                        </Card>
                    ))
                )}
            </div>

        </div>
    );
};

import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Card } from '../../../../components/ui/Card';
import { Button } from '../../../../components/ui/Button';
import { useAuth } from '../../../../hooks/useAuth';

export const ChurchSelect: FC = () => {
    const { target } = useParams<{ target: string }>();
    const navigate = useNavigate();
    const { isMaster } = useAuth();
    const [churches, setChurches] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        fetchMyChurches();
    }, []);

    const fetchMyChurches = async () => {
        try {
            const token = localStorage.getItem('auth_token');
            const response = await fetch('/api/churches?action=my_churches', {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await response.json();

            if (data.success) {
                if (data.churches.length === 1) {
                    // Auto-redirect if only one church
                    redirectToTarget(data.churches[0].id);
                } else if (data.churches.length === 0) {
                    if (isMaster) {
                        // For Master, 0 churches is an invitation to create one
                        setChurches([]);
                    } else {
                        setError('No tienes iglesias asociadas.');
                    }
                } else {
                    setChurches(data.churches);
                }
            } else {
                setError(data.message || 'Error al cargar iglesias.');
            }
        } catch (err) {
            setError('Estamos presentando demoras en el servicio, intentelo m├ís tarde.');
        } finally {
            setIsLoading(false);
        }
    };

    const redirectToTarget = (churchId: number) => {
        let path = '/';
        if (target === 'teams') path = `/mainhub/teams?church_id=${churchId}`;
        else if (target === 'areas') path = `/mainhub/setup-areas?church_id=${churchId}`;
        else if (target === 'songs') path = `/worship/songs?church_id=${churchId}`;
        else if (target === 'reports') path = `/mainhub/reports?church_id=${churchId}`;
        else if (target === 'ushers') path = `/mainhub/ushers?church_id=${churchId}`;

        navigate(path);
    };

    if (isLoading) return <div className="flex-center" style={{ height: '300px' }}><div className="spinner" /></div>;

    return (
        <div style={{ maxWidth: '500px', margin: '40px auto', padding: '0 20px' }}>
            <header style={{ marginBottom: '24px', textAlign: 'center' }}>
                <h1 className="text-h1">Seleccionar Iglesia</h1>
                <p className="text-body" style={{ color: 'gray' }}>Parece que perteneces a m├║ltiples iglesias. Por favor selecciona una para continuar.</p>
            </header>

            {error && (
                <Card style={{ padding: '16px', backgroundColor: 'rgba(239, 68, 68, 0.1)', color: '#EF4444', marginBottom: '16px', border: '1px solid rgba(239, 68, 68, 0.2)' }}>
                    {error}
                </Card>
            )}

            {churches.length > 0 ? (
                <div style={{ display: 'grid', gap: '12px' }}>
                    {churches.map(church => (
                        <Card
                            key={church.id}
                            onClick={() => redirectToTarget(church.id)}
                            style={{
                                display: 'flex', alignItems: 'center', gap: '16px', padding: '20px',
                                cursor: 'pointer', transition: 'transform 0.2s'
                            }}
                        >
                            <div style={{
                                width: '40px', height: '40px', borderRadius: '10px',
                                backgroundColor: 'rgba(59, 130, 246, 0.1)',
                                display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--color-brand-blue)'
                            }}>
                                <span className="material-symbols-outlined">church</span>
                            </div>
                            <div style={{ flex: 1 }}>
                                <h3 className="text-card-title">{church.name}</h3>
                                <p className="text-overline" style={{ color: 'gray' }}>/{church.slug}</p>
                            </div>
                            <span className="material-symbols-outlined" style={{ color: 'gray' }}>chevron_right</span>
                        </Card>
                    ))}
                </div>
            ) : isMaster && !error ? (
                <Card style={{ padding: '32px', textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '16px' }}>
                    <div style={{
                        width: '64px', height: '64px', borderRadius: '20px',
                        backgroundColor: 'rgba(59, 130, 246, 0.1)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--color-brand-blue)'
                    }}>
                        <span className="material-symbols-outlined" style={{ fontSize: '32px' }}>add_business</span>
                    </div>
                    <div>
                        <h3 className="text-h3">No hay iglesias registradas</h3>
                        <p className="text-body" style={{ color: 'gray', marginTop: '4px' }}>Para configurar equipos o ver reportes, primero debes crear una iglesia.</p>
                    </div>
                    <Button
                        variant="primary"
                        label="Crear mi primera iglesia"
                        icon="add"
                        onClick={() => navigate('/mainhub/churches/new')}
                    />
                </Card>
            ) : null}

            <div style={{ marginTop: '24px', textAlign: 'center' }}>
                <Button variant="ghost" label="Volver al Inicio" onClick={() => navigate('/')} />
            </div>
        </div>
    );
};

