import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Card } from '../../../components/ui/Card';
import { Button } from '../../../components/ui/Button';
import { songService } from '../../../services/songService';
import type { SongEdit, Song } from '../../../types/domain';

export const PendingApprovals: FC = () => {
    const { t } = useTranslation();
    const [edits, setEdits] = useState<SongEdit[]>([]);
    const [songs, setSongs] = useState<Record<string, Song>>({});
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        const [pendingEdits, allSongs] = await Promise.all([
            songService.getPendingEdits(),
            songService.getAll()
        ]);

        const songMap: Record<string, Song> = {};
        allSongs.forEach(s => { songMap[s.id.toString()] = s; });

        setSongs(songMap);
        setEdits(pendingEdits);
        setLoading(false);
    };

    const handleApprove = async (editId: number) => {
        if (confirm(t('songs.moderation.approveConfirm'))) {
            const success = await songService.approveEdit(editId);
            if (success) {
                setEdits(edits.filter(e => e.id !== editId));
            }
        }
    };

    const handleReject = async (editId: number) => {
        const notes = prompt(t('songs.moderation.rejectionReason'));
        if (notes !== null) {
            const success = await songService.rejectEdit(editId, notes);
            if (success) {
                setEdits(edits.filter(e => e.id !== editId));
            }
        }
    };

    if (loading) return <div style={{ textAlign: 'center' }}>{t('common.loading')}</div>;

    return (
        <div style={{ maxWidth: '1000px', margin: '0 auto', padding: '16px' }}>
            <header style={{ marginBottom: '24px' }}>
                <h1 className="text-h1">{t('songs.moderation.title')}</h1>
                <p className="text-body" style={{ color: 'gray' }}>{t('songs.moderation.subtitle')}</p>
            </header>

            {edits.length === 0 ? (
                <Card style={{ padding: '40px', textAlign: 'center' }}>
                    <span className="material-symbols-outlined" style={{ fontSize: '48px', color: '#ccc', marginBottom: '16px' }}>check_circle</span>
                    <p className="text-body" style={{ color: 'gray' }}>{t('songs.moderation.empty')}</p>
                </Card>
            ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                    {edits.map(edit => {
                        const original = songs[edit.songId.toString()];
                        return (
                            <Card key={edit.id} style={{ padding: '20px' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
                                    <div>
                                        <h3 className="text-card-title" style={{ margin: 0 }}>{original?.title || t('songs.notFound')}</h3>
                                        <p className="text-overline" style={{ color: 'var(--color-brand-blue)', marginTop: '4px' }}>
                                            {t('songs.moderation.proposedBy', {
                                                name: `Usuario ID ${edit.memberId}`,
                                                date: new Date(edit.createdAt).toLocaleDateString()
                                            })}
                                        </p>
                                    </div>
                                    <div style={{ display: 'flex', gap: '8px' }}>
                                        <Button variant="secondary" label={t('songs.moderation.reject')} onClick={() => handleReject(edit.id)} style={{ color: '#ff4444' }} />
                                        <Button variant="primary" label={t('songs.moderation.approve')} onClick={() => handleApprove(edit.id)} />
                                    </div>
                                </div>

                                <div className="diff-container" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '24px', backgroundColor: 'var(--color-ui-bg)', padding: '16px', borderRadius: '8px' }}>
                                    <div>
                                        <label className="text-overline" style={{ color: 'gray', display: 'block', marginBottom: '8px' }}>{t('songs.moderation.currentVersion')}</label>
                                        <div style={{ whiteSpace: 'pre-wrap', fontSize: '13px', fontFamily: 'monospace', opacity: 0.7 }}>
                                            {original?.content || '(Sin contenido)'}
                                        </div>
                                    </div>
                                    <div>
                                        <label className="text-overline" style={{ color: 'var(--color-brand-blue)', display: 'block', marginBottom: '8px' }}>{t('songs.moderation.proposedVersion')}</label>
                                        <div style={{ whiteSpace: 'pre-wrap', fontSize: '13px', fontFamily: 'monospace', color: 'var(--color-ui-text)' }}>
                                            {edit.proposedContent || original?.content}
                                        </div>
                                        {(edit.proposedKey && edit.proposedKey !== original?.originalKey) && (
                                            <p style={{ fontSize: '12px', marginTop: '12px' }}>
                                                {t('songs.moderation.keyChange', { from: original?.originalKey, to: edit.proposedKey })}
                                            </p>
                                        )}
                                        {(edit.proposedTempo && edit.proposedTempo !== original?.tempo) && (
                                            <p style={{ fontSize: '12px' }}>
                                                {t('songs.moderation.tempoChange', { from: original?.tempo, to: edit.proposedTempo })}
                                            </p>
                                        )}
                                    </div>
                                </div>
                            </Card>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

import type { FC } from 'react';
import { useEffect, useState, useMemo } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Button } from '../../../components/ui/Button';
import { Card } from '../../../components/ui/Card';
import { ChordSheetRenderer } from '../../../components/music/ChordSheetRenderer';
import type { ChordViewMode } from '../../../components/music/ChordSheetRenderer';
import { Metronome } from '../../../components/music/Metronome';
import { songService } from '../../../services/songService';
import type { Song } from '../../../services/songService';
import { musicUtils } from '../../../utils/musicUtils';

export const SongDetail: FC = () => {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const location = useLocation();
    const { t } = useTranslation();

    const [song, setSong] = useState<Song | undefined>(undefined);
    const [loading, setLoading] = useState(true);

    // Get query params
    const queryParams = useMemo(() => new URLSearchParams(location.search), [location.search]);
    const initialSingerId = queryParams.get('singer');

    // Musical State
    const [transpose, setTranspose] = useState(0);
    const [viewMode, setViewMode] = useState<ChordViewMode>('american');
    const [selectedSingerId, setSelectedSingerId] = useState<number | null>(null);
    const [fontSize, setFontSize] = useState(16);

    useEffect(() => {
        if (id) loadSong(id);
    }, [id]);

    const handleSingerChange = (singerId: number | null) => {
        setSelectedSingerId(singerId);
        if (singerId === null || !song) {
            setTranspose(0);
            return;
        }

        const assignment = song.memberKeys?.find(mk => mk.memberId === singerId);
        if (assignment) {
            const originalIdx = musicUtils.getSemitoneIndex(song.originalKey);
            const targetIdx = musicUtils.getSemitoneIndex(assignment.preferredKey);
            let diff = targetIdx - originalIdx;
            while (diff > 6) diff -= 12;
            while (diff <= -6) diff += 12;

            setTranspose(diff);
        }
    };

    const loadSong = async (songId: string) => {
        try {
            setLoading(true);
            const data = await songService.getById(songId);
            setSong(data);

            if (data && initialSingerId) {
                const singerIdNum = parseInt(initialSingerId);
                const assignment = data.memberKeys?.find(mk => mk.memberId === singerIdNum);
                if (assignment) {
                    setSelectedSingerId(singerIdNum);
                    const originalIdx = musicUtils.getSemitoneIndex(data.originalKey);
                    const targetIdx = musicUtils.getSemitoneIndex(assignment.preferredKey);
                    let diff = targetIdx - originalIdx;
                    while (diff > 6) diff -= 12;
                    while (diff <= -6) diff += 12;
                    setTranspose(diff);
                }
            }
        } finally {
            setLoading(false);
        }
    };

    if (loading) return <div className="p-4 text-center">{t('common.loading')}</div>;
    if (!song) return <div className="p-4 text-center">{t('songs.notFound')}</div>;

    // Calculate current key based on transposition
    const currentKey = musicUtils.transposeNote(song.originalKey, transpose);

    return (
        <div style={{ padding: '24px', paddingBottom: '100px', display: 'flex', flexDirection: 'column', gap: '8px', width: '100%', minWidth: 0 }}>
            {/* Minimal Header / Navigation */}
            <div style={{ display: 'flex', alignItems: 'center', padding: '8px 4px' }}>
                <Button
                    variant="ghost"
                    onClick={() => navigate('/worship/songs' + (song.churchId ? `?church_id=${song.churchId}` : ''))}
                    style={{ padding: '8px', marginRight: '4px' }}
                >
                    <span className="material-symbols-outlined">arrow_back</span>
                </Button>
                <div style={{ flex: 1, overflow: 'hidden' }}>
                    <h1 className="text-h2" style={{ margin: 0, whiteSpace: 'nowrap', textOverflow: 'ellipsis', overflow: 'hidden' }}>{song.title}</h1>
                    <p className="text-overline" style={{ margin: 0, color: 'gray' }}>{song.artist}</p>
                </div>
                <Button
                    variant="ghost"
                    onClick={() => navigate(`/worship/songs/${id}/edit`)}
                    style={{ padding: '8px' }}
                >
                    <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>edit</span>
                </Button>
            </div>

            {/* Desktop 3-Column Layout */}
            <div style={{
                display: 'grid',
                gridTemplateColumns: 'minmax(0, 1fr)',
                gap: '24px',
                alignItems: 'start'
            }} className="song-detail-grid">
                <style>{`
                    @media (min-width: 1200px) {
                    .song-detail-grid {
                        grid-template-columns: repeat(3, 1fr);
                    }
                }
                `}</style>

                {/* Column 1: Controls & Info */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                    <Card style={{ padding: '20px' }}>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                            <div style={{ display: 'flex', flexDirection: 'column' }}>
                                <span className="text-overline" style={{ fontSize: '10px', color: 'var(--color-ui-text-soft)' }}>TONALIDAD</span>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginTop: '4px' }}>
                                    <span className="text-h1" style={{ fontSize: '32px', color: 'var(--color-brand-blue)', lineHeight: 1 }}>{currentKey}</span>
                                    {transpose !== 0 && <span className="text-overline" style={{ opacity: 0.5 }}>({song.originalKey})</span>}
                                </div>
                            </div>

                            <div style={{ display: 'flex', gap: '4px' }}>
                                <Button variant="secondary" onClick={() => setTranspose(p => p - 1)} style={{ flex: 1, height: '36px' }} label="-" />
                                <Button variant="secondary" onClick={() => setTranspose(0)} style={{ flex: 1.5, height: '36px', fontWeight: 'bold' }} label="Reset" />
                                <Button variant="secondary" onClick={() => setTranspose(p => p + 1)} style={{ flex: 1, height: '36px' }} label="+" />
                            </div>

                            <div className="dropdown-divider" style={{ margin: '4px 0' }} />

                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                                <div>
                                    <span className="text-overline" style={{ fontSize: '9px' }}>TEMPO</span>
                                    <p style={{ fontWeight: 700, margin: 0 }}>{song.tempo} BPM</p>
                                </div>
                                <div>
                                    <span className="text-overline" style={{ fontSize: '9px' }}>COMP├üS</span>
                                    <p style={{ fontWeight: 700, margin: 0 }}>{song.timeSignature || '4/4'}</p>
                                </div>
                            </div>

                            {song.tempo && <Metronome bpm={song.tempo} variant="card" />}
                        </div>
                    </Card>

                    <Card style={{ padding: '20px' }}>
                        <h4 className="text-overline" style={{ marginBottom: '12px' }}>CONFIGURACI├ôN</h4>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                            <div>
                                <label className="text-overline" style={{ fontSize: '9px', display: 'block', marginBottom: '4px' }}>NOTACI├ôN</label>
                                <div style={{ display: 'flex', backgroundColor: 'var(--color-ui-surface)', borderRadius: '10px', padding: '3px', gap: '2px' }}>
                                    {['american', 'spanish', 'roman', 'lyrics'].map((mode) => (
                                        <button
                                            key={mode}
                                            onClick={() => setViewMode(mode as any)}
                                            style={{
                                                flex: 1,
                                                padding: '6px 0',
                                                fontSize: '10px',
                                                fontWeight: 700,
                                                border: 'none',
                                                borderRadius: '7px',
                                                cursor: 'pointer',
                                                backgroundColor: viewMode === mode ? 'var(--color-brand-blue)' : 'transparent',
                                                color: viewMode === mode ? 'white' : 'var(--color-ui-text-soft)',
                                                transition: 'all 0.2s'
                                            }}
                                        >
                                            {mode === 'american' ? 'AM' : mode === 'spanish' ? 'LA' : mode === 'roman' ? 'VM' : 'TXT'}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {song.memberKeys && song.memberKeys.length > 0 && (
                                <div>
                                    <label className="text-overline" style={{ fontSize: '9px', display: 'block', marginBottom: '4px' }}>CANTANTE</label>
                                    <select
                                        className="text-body"
                                        value={selectedSingerId || ''}
                                        onChange={e => handleSingerChange(e.target.value ? parseInt(e.target.value) : null)}
                                        style={{
                                            width: '100%',
                                            background: 'var(--color-ui-surface)',
                                            border: '1px solid var(--color-border-subtle)',
                                            borderRadius: '8px',
                                            color: 'var(--color-ui-text)',
                                            padding: '8px',
                                            fontSize: '12px'
                                        }}
                                    >
                                        <option value="">Original</option>
                                        {song.memberKeys.map(mk => (
                                            <option key={mk.memberId} value={mk.memberId}>{mk.memberName}</option>
                                        ))}
                                    </select>
                                </div>
                            )}

                            <div>
                                <label className="text-overline" style={{ fontSize: '9px', display: 'block', marginBottom: '4px' }}>TAMA├æO LETRA</label>
                                <div style={{ display: 'flex', gap: '4px', alignItems: 'center' }}>
                                    <Button variant="ghost" onClick={() => setFontSize(s => Math.max(10, s - 2))} style={{ flex: 1, height: '32px' }} label="-" />
                                    <span style={{ flex: 1, textAlign: 'center', fontWeight: 700, fontSize: '12px' }}>{fontSize}</span>
                                    <Button variant="ghost" onClick={() => setFontSize(s => Math.min(30, s + 2))} style={{ flex: 1, height: '32px' }} label="+" />
                                </div>
                            </div>
                        </div>
                    </Card>
                </div>

                {/* Column 2: The Sheet */}
                <Card style={{ padding: '32px', minHeight: '600px', borderRadius: '24px' }}>
                    <ChordSheetRenderer
                        content={song.content}
                        transpose={transpose}
                        viewMode={viewMode}
                        songKey={song.originalKey}
                        fontSize={fontSize}
                    />
                </Card>

                {/* Column 3: Multimedia & Resources */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                    {song.youtubeUrl && (
                        <Card style={{ padding: '12px', overflow: 'hidden' }}>
                            <h4 className="text-overline" style={{ marginBottom: '12px', marginLeft: '8px' }}>VIDEO REFERENCIA</h4>
                            <div style={{ position: 'relative', paddingBottom: '56.25%', height: 0, borderRadius: '12px', overflow: 'hidden', backgroundColor: '#000' }}>
                                <iframe
                                    style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', border: 0 }}
                                    src={`https://www.youtube.com/embed/${song.youtubeUrl.split('v=')[1]?.split('&')[0] || song.youtubeUrl.split('/').pop()}`}
                                    title="YouTube video player"
                                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                                    allowFullScreen
                                />
                            </div>
                        </Card>
                    )}

                    <Card style={{ padding: '20px' }}>
                        <h4 className="text-overline" style={{ marginBottom: '16px' }}>VERSIONES</h4>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '10px', borderRadius: '12px', backgroundColor: 'var(--color-ui-surface)' }}>
                                <span className="material-symbols-outlined" style={{ color: 'var(--color-brand-blue)' }}>description</span>
                                <div style={{ flex: 1 }}>
                                    <p style={{ fontSize: '13px', fontWeight: 600, margin: 0 }}>Acordes Originales</p>
                                    <p style={{ fontSize: '11px', color: 'var(--color-ui-text-soft)', margin: 0 }}>PDF ÔÇó 120 KB</p>
                                </div>
                                <Button variant="ghost" icon="download" style={{ minWidth: 'auto', padding: '6px' }} />
                            </div>
                            {/* Hidden file upload logic here if needed, but UI wise we just show versions */}
                        </div>
                    </Card>
                </div>
            </div>
        </div>
    );
};

import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate, useParams, useSearchParams } from 'react-router-dom';
import { Card } from '../../../components/ui/Card';
import { Button } from '../../../components/ui/Button';
import { songService } from '../../../services/songService';
import type { Song, MemberKey, User } from '../../../types/domain';
import { useAuth } from '../../../hooks/useAuth';
import { useToast } from '../../../context/ToastContext';

import { peopleService } from '../../../services/peopleService';

const MUSICAL_KEYS = ['C', 'C#', 'Db', 'D', 'Eb', 'E', 'F', 'F#', 'Gb', 'G', 'Ab', 'A', 'Bb', 'B'];

export const SongEditor: FC = () => {
    const { t } = useTranslation();
    const navigate = useNavigate();
    const { id } = useParams<{ id: string }>();
    const [searchParams] = useSearchParams();
    const isEditing = !!id && id !== 'new';

    const [form, setForm] = useState<Omit<Song, 'id' | 'churchId'>>({
        title: '',
        artist: '',
        originalKey: 'C',
        tempo: 120,
        timeSignature: '4/4',
        content: '',
        category: 'worship',
        bpmType: 'fast',
        youtubeUrl: '',
        spotifyUrl: '',
        memberKeys: []
    });

    const [loading, setLoading] = useState(false);
    const { user, isMaster } = useAuth();
    const { addToast } = useToast();
    const [singers, setSingers] = useState<User[]>([]);

    const churchIdFromUrl = searchParams.get('church_id') ? parseInt(searchParams.get('church_id')!) : null;
    const isPastor = user?.role?.name === 'pastor';
    const finalChurchId = churchIdFromUrl || user?.churchId;

    useEffect(() => {
        // Redirect if no church context and NOT a Master user (who can create global songs)
        if (!finalChurchId && !isMaster && isPastor) {
            navigate('/mainhub/select-church/songs');
            return;
        }

        peopleService.getAll(finalChurchId || undefined).then(setSingers);
    }, [finalChurchId, isMaster, isPastor, navigate]);

    useEffect(() => {
        if (isEditing) {
            loadSong();
        }
    }, [id]);

    const loadSong = async () => {
        const song = await songService.getById(id!, finalChurchId || undefined);
        if (song) {
            setForm({
                title: song.title,
                artist: song.artist,
                originalKey: song.originalKey,
                tempo: song.tempo || 120,
                timeSignature: song.timeSignature || '4/4',
                content: song.content,
                category: song.category || 'worship',
                bpmType: song.bpmType || 'fast',
                youtubeUrl: song.youtubeUrl || '',
                spotifyUrl: (song as any).spotifyUrl || '',
                memberKeys: song.memberKeys || []
            });
        }
    };

    const addMemberKey = () => {
        if (singers.length === 0) {
            addToast(t('people.noSingers') || 'No hay cantantes registrados para asignar.', 'warning');
            return;
        }
        const firstAvailableSinger = singers[0];
        const newAssignment: MemberKey = {
            songId: id || 'new',
            memberId: firstAvailableSinger.id,
            memberName: firstAvailableSinger.name,
            preferredKey: form.originalKey
        };
        setForm({ ...form, memberKeys: [...(form.memberKeys || []), newAssignment] });
    };

    const removeMemberKey = (index: number) => {
        const updated = [...(form.memberKeys || [])];
        updated.splice(index, 1);
        setForm({ ...form, memberKeys: updated });
    };

    const updateMemberKey = (index: number, field: keyof MemberKey, value: any) => {
        const updated = [...(form.memberKeys || [])];
        const item = { ...updated[index], [field]: value };

        if (field === 'memberId') {
            const singer = singers.find(s => s.id === parseInt(value));
            item.memberName = singer?.name || '';
        }

        updated[index] = item;
        setForm({ ...form, memberKeys: updated });
    };

    const handleSave = async () => {
        if (!user) return;
        setLoading(true);

        try {
            // Direct edit bypass for Master, Pastor, Leader
            const isAuthorizedToDirectEdit =
                (user.role?.level !== undefined && user.role.level <= 30);

            if (isEditing) {
                if (isAuthorizedToDirectEdit) {
                    await songService.update(id!, form);
                    addToast(t('songs.saveSuccess') || 'Cambios guardados correctamente.', 'success');
                } else {
                    // Members must submit for approval
                    await songService.submitEdit({
                        songId: id!,
                        memberId: user.id,
                        proposedTitle: form.title,
                        proposedArtist: form.artist,
                        proposedContent: form.content,
                        proposedKey: form.originalKey,
                        proposedTempo: form.tempo,
                        proposedTimeSignature: form.timeSignature,
                        proposedBpmType: form.bpmType
                    });
                    addToast(t('songs.submitApprovalSuccess') || 'Tus cambios han sido enviados para revisi├│n por un l├¡der.', 'success');
                }
            } else {
                // New songs likewise: leaders add directly, members submit?
                // For now, let's allow adding directly or keep it simple
                await songService.add(form, finalChurchId || undefined);
                addToast(t('songs.addSuccess') || 'Canci├│n a├▒adida correctamente.', 'success');
            }
            navigate('/worship/songs' + (finalChurchId ? `?church_id=${finalChurchId}` : ''));
        } catch (error: any) {
            console.error('Save failed', error);
            if (error.response?.status === 403) {
                addToast(t('songs.forbiddenEdit') || 'No tienes permisos para editar esta canci├│n directamente.', 'error');
            } else {
                addToast(t('common.error') || 'Ocurri├│ un error al guardar.', 'error');
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ width: '100%', padding: '24px', minWidth: 0 }}>
            <style>{`
                .editor-grid {
                    display: grid;
                    grid-template-columns: 1fr;
                    gap: 24px;
                    align-items: start;
                }
                @media (min-width: 1200px) {
                    .editor-grid {
                        grid-template-columns: repeat(3, 1fr);
                    }
                }
                @media (min-width: 768px) and (max-width: 1199px) {
                    .editor-grid {
                        grid-template-columns: 1fr 1fr;
                    }
                }
            `}</style>
            <header style={{ marginBottom: '32px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                    <Button variant="ghost" icon="arrow_back" label={t('common.back') || 'Volver'} onClick={() => navigate(-1)} style={{ marginBottom: '8px', padding: 0 }} />
                    <h1 className="text-h1">{isEditing ? t('songs.edit') : t('songs.add')}</h1>
                </div>
                <div style={{ display: 'flex', gap: '12px' }}>
                    <Button variant="secondary" label={t('common.cancel')} onClick={() => navigate(-1)} />
                    <Button variant="primary" label={loading ? t('common.save') + '...' : t('common.save')} onClick={handleSave} disabled={loading} />
                </div>
            </header>

            <div className="editor-grid">
                {/* Column 1: Config & Resource Info */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
                    <Card style={{ padding: '24px' }}>
                        <h3 className="text-card-title" style={{ marginBottom: '16px' }}>{t('songs.basicInfo') || 'Informaci├│n B├ísica'}</h3>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                            <div>
                                <label className="text-overline" style={{ color: 'var(--color-ui-text-soft)', marginBottom: '6px', display: 'block' }}>{t('songs.title') || 'T├¡tulo'}</label>
                                <input className="text-body" value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} style={inputStyle} placeholder={t('songs.titlePlaceholder') || 'Nombre de la canci├│n'} />
                            </div>
                            <div>
                                <label className="text-overline" style={{ color: 'var(--color-ui-text-soft)', marginBottom: '6px', display: 'block' }}>{t('songs.artist') || 'Artista'}</label>
                                <input className="text-body" value={form.artist} onChange={e => setForm({ ...form, artist: e.target.value })} style={inputStyle} placeholder={t('songs.artistPlaceholder') || 'Nombre del artista/grupo'} />
                            </div>
                        </div>
                    </Card>

                    <Card style={{ padding: '24px' }}>
                        <h3 className="text-card-title" style={{ marginBottom: '16px' }}>{t('songs.technical') || 'Detalles T├®cnicos'}</h3>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                                <div>
                                    <label className="text-overline" style={{ color: 'var(--color-ui-text-soft)', marginBottom: '6px', display: 'block' }}>{t('songs.key') || 'Tonalidad'}</label>
                                    <select className="text-body" value={form.originalKey} onChange={e => setForm({ ...form, originalKey: e.target.value })} style={inputStyle}>
                                        {MUSICAL_KEYS.map(k => <option key={k} value={k}>{k}</option>)}
                                    </select>
                                </div>
                                <div>
                                    <label className="text-overline" style={{ color: 'var(--color-ui-text-soft)', marginBottom: '6px', display: 'block' }}>{t('songs.bpmType') || 'Tipo BPM'}</label>
                                    <select className="text-body" value={form.bpmType || 'fast'} onChange={e => setForm({ ...form, bpmType: e.target.value as 'fast' | 'slow' })} style={inputStyle}>
                                        <option value="fast">{t('songs.fast') || 'R├ípida'}</option>
                                        <option value="slow">{t('songs.slow') || 'Lenta'}</option>
                                    </select>
                                </div>
                            </div>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                                <div>
                                    <label className="text-overline" style={{ color: 'var(--color-ui-text-soft)', marginBottom: '6px', display: 'block' }}>BPM</label>
                                    <input type="number" className="text-body" value={form.tempo} onChange={e => setForm({ ...form, tempo: parseInt(e.target.value) })} style={inputStyle} />
                                </div>
                                <div>
                                    <label className="text-overline" style={{ color: 'var(--color-ui-text-soft)', marginBottom: '6px', display: 'block' }}>{t('songs.time') || 'Comp├ís'}</label>
                                    <select className="text-body" value={form.timeSignature} onChange={e => setForm({ ...form, timeSignature: e.target.value })} style={inputStyle}>
                                        {['4/4', '3/4', '6/8', '2/4', '2/2', '5/4', '12/8'].map(ts => <option key={ts} value={ts}>{ts}</option>)}
                                    </select>
                                </div>
                            </div>
                        </div>
                    </Card>

                    <Card style={{ padding: '24px' }}>
                        <h3 className="text-card-title" style={{ marginBottom: '16px' }}>{t('songs.multimedia') || 'Multimedia'}</h3>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                            <div>
                                <label className="text-overline" style={{ color: 'var(--color-ui-text-soft)', marginBottom: '6px', display: 'block' }}>YouTube Link</label>
                                <div style={{ position: 'relative' }}>
                                    <span className="material-symbols-outlined" style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: '#FF0000', fontSize: '18px' }}>smart_display</span>
                                    <input className="text-body" value={form.youtubeUrl} onChange={e => setForm({ ...form, youtubeUrl: e.target.value })} style={{ ...inputStyle, paddingLeft: '40px' }} placeholder="https://youtube.com/..." />
                                </div>
                            </div>
                            <div>
                                <label className="text-overline" style={{ color: 'var(--color-ui-text-soft)', marginBottom: '6px', display: 'block' }}>Spotify Link</label>
                                <div style={{ position: 'relative' }}>
                                    <span className="material-symbols-outlined" style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: '#1DB954', fontSize: '18px' }}>album</span>
                                    <input className="text-body" value={(form as any).spotifyUrl} onChange={e => setForm({ ...form, ['spotifyUrl' as any]: e.target.value })} style={{ ...inputStyle, paddingLeft: '40px' }} placeholder="https://spotify.com/..." />
                                </div>
                            </div>
                        </div>
                    </Card>
                </div>

                {/* Column 2: Singer Assignments & Editor */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
                    <Card style={{ padding: '24px' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                            <h3 className="text-card-title" style={{ fontSize: '14px' }}>{t('songs.singerAssignments') || 'L├¡der de Alabanza'}</h3>
                            <Button variant="ghost" icon="add" onClick={addMemberKey} style={{ padding: '4px', minWidth: 'auto' }} />
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                            {form.memberKeys && form.memberKeys.map((mk, idx) => (
                                <div key={idx} style={{ display: 'flex', gap: '6px', alignItems: 'center', backgroundColor: 'var(--color-ui-surface)', padding: '8px', borderRadius: '10px' }}>
                                    <select className="text-body" value={mk.memberId} onChange={e => updateMemberKey(idx, 'memberId', e.target.value)} style={{ ...inputStyle, flex: 2, padding: '4px 8px', fontSize: '12px' }}>
                                        {singers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                                    </select>
                                    <select className="text-body" value={mk.preferredKey} onChange={e => updateMemberKey(idx, 'preferredKey', e.target.value)} style={{ ...inputStyle, flex: 1, padding: '4px 4px', fontSize: '12px' }}>
                                        {MUSICAL_KEYS.map(k => <option key={k} value={k}>{k}</option>)}
                                    </select>
                                    <button onClick={() => removeMemberKey(idx)} style={{ background: 'none', border: 'none', color: 'var(--color-danger-red)', cursor: 'pointer', padding: '2px' }}>
                                        <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>delete</span>
                                    </button>
                                </div>
                            ))}
                            {(!form.memberKeys || form.memberKeys.length === 0) && (
                                <p className="text-body-secondary" style={{ textAlign: 'center', fontSize: '12px' }}>{t('songs.noSingersAssigned')}</p>
                            )}
                        </div>
                    </Card>

                    <Card style={{ padding: '24px', minHeight: '600px', display: 'flex', flexDirection: 'column' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px', flexWrap: 'wrap', gap: '8px' }}>
                            <label className="text-overline" style={{ color: 'var(--color-ui-text-soft)', margin: 0 }}>{t('songs.contentLabel')}</label>
                            <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap' }}>
                                {[
                                    { n: 'Intro', c: '#6B7280' },
                                    { n: 'Estrofa', c: '#3B82F6' },
                                    { n: 'Coro', c: '#10B981' },
                                    { n: 'Puente', c: '#F59E0B' },
                                    { n: 'Outro', c: '#EF4444' }
                                ].map(s => (
                                    <button
                                        key={s.n}
                                        onClick={() => {
                                            const textarea = document.getElementById('song-content-area') as HTMLTextAreaElement;
                                            if (!textarea) return;
                                            const start = textarea.selectionStart;
                                            const end = textarea.selectionEnd;
                                            const text = form.content;

                                            // Check if we are at start or need a prefix newline
                                            const needsPrefix = start > 0 && text[start - 1] !== '\n';
                                            const tag = `${needsPrefix ? '\n' : ''}[${s.n}]\n`;

                                            const before = text.substring(0, start);
                                            const after = text.substring(end);
                                            setForm({ ...form, content: before + tag + after });

                                            setTimeout(() => {
                                                textarea.focus();
                                                const cursorFixed = start + tag.length;
                                                textarea.setSelectionRange(cursorFixed, cursorFixed);
                                            }, 10);
                                        }}
                                        type="button"
                                        style={{
                                            border: 'none',
                                            borderRadius: '6px',
                                            padding: '4px 10px',
                                            fontSize: '10px',
                                            fontWeight: 400,
                                            backgroundColor: s.c,
                                            color: 'white',
                                            cursor: 'pointer',
                                            textTransform: 'uppercase'
                                        }}
                                    >
                                        {s.n}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <textarea
                            id="song-content-area"
                            className="text-body"
                            value={form.content}
                            onChange={e => setForm({ ...form, content: e.target.value })}
                            style={{
                                ...inputStyle,
                                flex: 1,
                                minHeight: '500px',
                                fontFamily: 'monospace',
                                resize: 'none',
                                lineHeight: '1.6',
                                padding: '20px'
                            }}
                            placeholder={t('songs.contentPlaceholder')}
                        />
                    </Card>
                </div>

                {/* Column 3: Preview */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
                    <Card style={{ padding: '24px' }}>
                        <h3 className="text-card-title" style={{ marginBottom: '16px' }}>{t('common.preview')}</h3>
                        <div style={{
                            fontFamily: 'monospace',
                            whiteSpace: 'pre-wrap',
                            lineHeight: '1.8',
                            color: 'var(--color-ui-text)',
                            fontSize: '11px',
                            maxHeight: '800px',
                            overflowY: 'auto',
                            backgroundColor: 'var(--color-ui-bg)',
                            padding: '16px',
                            borderRadius: '12px',
                            border: '1px solid var(--color-border-subtle)'
                        }}>
                            {form.content ? form.content.split('\n').map((line, i) => (
                                <p key={i} style={{ margin: 0 }}>
                                    {line.split(/(\[[^\]]+\])/).map((part, j) => (
                                        part.startsWith('[') ? (
                                            <span key={j} style={{ position: 'relative', display: 'inline-flex', width: 0, overflow: 'visible' }}>
                                                <strong style={{ position: 'absolute', bottom: '100%', left: 0, color: 'var(--color-brand-blue)', whiteSpace: 'nowrap', transform: 'translateY(10%)' }}>
                                                    {part.slice(1, -1)}
                                                </strong>
                                            </span>
                                        ) : part
                                    ))}
                                </p>
                            )) : <span style={{ color: 'var(--color-ui-text-soft)' }}>{t('songs.previewPlaceholder')}</span>}
                        </div>
                    </Card>
                </div>
            </div>

        </div>
    );
};

const inputStyle = {
    width: '100%',
    padding: '10px 12px',
    borderRadius: '8px',
    border: '1px solid var(--color-border-subtle)',
    backgroundColor: 'var(--color-ui-bg)',
    color: 'var(--color-ui-text)',
    fontSize: '14px',
    outline: 'none'
};

import type { FC } from 'react';
import { useEffect, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { Card } from '../../../components/ui/Card';
import { Button } from '../../../components/ui/Button';
import { songService } from '../../../services/songService';
import { useAuth } from '../../../hooks/useAuth';
import type { Song } from '../../../services/songService';
import { SongCard } from '../../../components/music/SongCard';
import { SongTable } from '../../../components/music/SongTable';
import { ChordSheetRenderer } from '../../../components/music/ChordSheetRenderer';
import type { ChordViewMode } from '../../../components/music/ChordSheetRenderer';
import { musicUtils } from '../../../utils/musicUtils';
import { peopleService } from '../../../services/peopleService';
import type { User } from '../../../types/domain';

export const SongList: FC = () => {
    const { t } = useTranslation();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const { hasPermission, isMaster, user } = useAuth();
    const [songs, setSongs] = useState<Song[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [singers, setSingers] = useState<User[]>([]);

    // Pagination
    const [page, setPage] = useState(1);
    const PAGE_SIZE = 20;

    // Advanced Filters
    const [filterKey, setFilterKey] = useState('');
    const [filterType, setFilterType] = useState<'' | 'fast' | 'slow'>('');
    const [filterSinger, setFilterSinger] = useState<number | null>(null);
    const [showFilters, setShowFilters] = useState(false);

    const churchId = searchParams.get('church_id') ? parseInt(searchParams.get('church_id')!) : null;
    const isPastor = user?.role?.name === 'pastor';
    const profileChurchId = user?.churchId;
    const finalChurchId = churchId || profileChurchId;

    useEffect(() => {
        // Redirect if no church context at all and user is Pastor (multitenant context)
        // Master users and Superadmins bypass selection and see global songs
        if (!finalChurchId && !isMaster && isPastor) {
            navigate('/mainhub/select-church/songs');
            return;
        }

        loadSongs();
        loadSingers();
    }, [finalChurchId, isMaster, isPastor]);

    const loadSingers = async () => {
        const data = await peopleService.getAll(finalChurchId || undefined);
        setSingers(data);
    };

    const loadSongs = async () => {
        try {
            setLoading(true);
            // Master users always see the global library regardless of church context
            const data = await songService.getAll(isMaster ? undefined : (finalChurchId || undefined));
            setSongs(data);
        } finally {
            setLoading(false);
        }
    };

    // Generate the list to display based on filters
    const getDisplaySongs = () => {
        let list: any[] = [...songs];

        // 1. If singer filter is active, we expand the list with assignments
        if (filterSinger) {
            list = [];
            songs.forEach(song => {
                const assignment = song.memberKeys?.find(mk => mk.memberId === filterSinger);
                if (assignment) {
                    list.push({
                        ...song,
                        originalKey: assignment.preferredKey,
                        isAssigned: true,
                        singerName: assignment.memberName
                    });
                }
            });
        }

        // 2. Search
        if (searchTerm) {
            list = list.filter(s =>
                s.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
                s.artist.toLowerCase().includes(searchTerm.toLowerCase())
            );
        }

        // 3. Category/Type Filter
        if (filterType) {
            list = list.filter(s => (s.bpmType || 'fast') === filterType);
        }

        // 4. Key Filter
        if (filterKey) {
            list = list.filter(s => s.originalKey === filterKey);
        }

        // 5. Alpha Sort
        list.sort((a, b) => a.title.localeCompare(b.title));

        return list;
    };

    const allFilteredSongs = getDisplaySongs();
    const visibleSongs = allFilteredSongs.slice(0, page * PAGE_SIZE);
    const hasMore = allFilteredSongs.length > (page * PAGE_SIZE);

    const [selectedSong, setSelectedSong] = useState<Song | null>(null);
    const [transpose, setTranspose] = useState(0);
    const [viewMode, setViewMode] = useState<ChordViewMode>('american');
    const [fontSize, setFontSize] = useState(14);

    const handleSelectSong = (song: Song) => {
        setSelectedSong(song);
        setTranspose(0);
    };

    return (
        <div style={{ position: 'relative', display: 'flex', gap: '24px', alignItems: 'start', padding: '24px' }}>
            <div style={{ flex: 1, minWidth: 0 }}>
                <header style={{ marginBottom: '24px' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                        <h1 className="text-h1">{t('songs.title')}</h1>
                        {hasPermission('songs.create') && (
                            <Button
                                variant="primary"
                                icon="add"
                                label={t('songs.add')}
                                onClick={() => navigate('/worship/songs/new' + (finalChurchId ? `?church_id=${finalChurchId}` : ''))}
                            />
                        )}
                    </div>

                    <div style={{ position: 'relative', display: 'flex', gap: '8px' }}>
                        <div style={{ position: 'relative', flex: 1 }}>
                            <span className="material-symbols-outlined text-muted" style={{
                                position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)'
                            }}>search</span>
                            <input
                                type="text"
                                placeholder={t('songs.search')}
                                value={searchTerm}
                                onChange={e => { setSearchTerm(e.target.value); setPage(1); }}
                                style={{
                                    width: '100%',
                                    padding: '12px 12px 12px 40px',
                                    borderRadius: '12px',
                                    border: '1px solid var(--color-border-subtle)',
                                    backgroundColor: 'var(--color-ui-bg)',
                                    color: 'var(--color-ui-text)',
                                    outline: 'none',
                                    fontSize: '14px'
                                }}
                            />
                        </div>
                        <Button
                            variant="secondary"
                            onClick={() => setShowFilters(!showFilters)}
                            icon="filter_list"
                        />
                    </div>

                    {showFilters && (
                        <Card style={{ padding: '16px', marginTop: '12px', display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(120px, 1fr))', gap: '12px' }}>
                            <div>
                                <label className="text-overline text-muted" style={{ display: 'block', marginBottom: '4px' }}>{t('songs.key')}</label>
                                <select
                                    value={filterKey}
                                    onChange={e => { setFilterKey(e.target.value); setPage(1); }}
                                    style={{ width: '100%', padding: '8px', borderRadius: '8px', backgroundColor: 'var(--color-ui-bg)', color: 'var(--color-ui-text)', border: '1px solid var(--color-border-subtle)', outline: 'none', fontSize: '13px' }}
                                >
                                    <option value="">{t('common.all')}</option>
                                    {['C', 'C#', 'Db', 'D', 'Eb', 'E', 'F', 'F#', 'Gb', 'G', 'Ab', 'A', 'Bb', 'B'].map(k => (
                                        <option key={k} value={k}>{k}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="text-overline text-muted" style={{ display: 'block', marginBottom: '4px' }}>{t('songs.typeLabel')}</label>
                                <select
                                    value={filterType}
                                    onChange={e => { setFilterType(e.target.value as any); setPage(1); }}
                                    style={{ width: '100%', padding: '8px', borderRadius: '8px', backgroundColor: 'var(--color-ui-bg)', color: 'var(--color-ui-text)', border: '1px solid var(--color-border-subtle)', outline: 'none', fontSize: '13px' }}
                                >
                                    <option value="">{t('common.all')}</option>
                                    <option value="fast">{t('songs.fast')}</option>
                                    <option value="slow">{t('songs.slow')}</option>
                                </select>
                            </div>
                            <div>
                                <label className="text-overline text-muted" style={{ display: 'block', marginBottom: '4px' }}>{t('songs.singerAssignments')}</label>
                                <select
                                    value={filterSinger || ''}
                                    onChange={e => { setFilterSinger(e.target.value ? parseInt(e.target.value) : null); setPage(1); }}
                                    style={{ width: '100%', padding: '8px', borderRadius: '8px', backgroundColor: 'var(--color-ui-bg)', color: 'var(--color-ui-text)', border: '1px solid var(--color-border-subtle)', outline: 'none', fontSize: '13px' }}
                                >
                                    <option value="">{t('common.general')}</option>
                                    {singers.map(s => (
                                        <option key={s.id} value={s.id}>{s.name}</option>
                                    ))}
                                </select>
                            </div>
                        </Card>
                    )}
                </header>

                <div className="mobile-only" style={{ display: 'grid', gap: '8px' }}>
                    {loading ? (
                        <p className="text-body" style={{ textAlign: 'center', color: 'gray' }}>{t('common.loading')}</p>
                    ) : visibleSongs.length === 0 ? (
                        <p className="text-body" style={{ textAlign: 'center', color: 'gray', marginTop: '40px' }}>{t('songs.noSongs')}</p>
                    ) : (
                        <>
                            {visibleSongs.map(song => (
                                <SongCard
                                    key={`${song.id}-${song.isAssigned ? 'assigned' : 'orig'}`}
                                    song={song}
                                    singerIdFilter={filterSinger}
                                />
                            ))}

                            {hasMore && (
                                <Button
                                    variant="secondary"
                                    onClick={() => setPage(p => p + 1)}
                                    style={{ marginTop: '12px', width: '100%' }}
                                >
                                    {t('songs.loadMore')}
                                </Button>
                            )}
                        </>
                    )}
                </div>

                <div className="desktop-only">
                    {loading ? (
                        <div className="flex-center" style={{ height: '200px' }}><div className="spinner" /></div>
                    ) : visibleSongs.length === 0 ? (
                        <Card style={{ padding: '60px', textAlign: 'center' }}>
                            <span className="material-symbols-outlined" style={{ fontSize: '48px', color: 'var(--color-ui-text-soft)', marginBottom: '16px' }}>library_music</span>
                            <p className="text-body" style={{ color: 'gray' }}>{t('songs.noSongs')}</p>
                        </Card>
                    ) : (
                        <>
                            <SongTable
                                songs={visibleSongs}
                                singerIdFilter={filterSinger}
                                onSelect={handleSelectSong}
                                selectedId={selectedSong?.id.toString()}
                            />

                            {hasMore && (
                                <div style={{ display: 'flex', justifyContent: 'center', marginTop: '32px' }}>
                                    <Button
                                        variant="secondary"
                                        onClick={() => setPage(p => p + 1)}
                                        style={{ width: '240px' }}
                                    >
                                        {t('songs.loadMore')}
                                    </Button>
                                </div>
                            )}
                        </>
                    )}
                </div>
            </div>

            {/* Quick Preview Aside */}
            {selectedSong && (
                <>
                    {/* Backdrop for mobile focus */}
                    <div
                        className="mobile-only"
                        style={{ position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.4)', zIndex: 100, backdropFilter: 'blur(4px)' }}
                        onClick={() => setSelectedSong(null)}
                    />
                    <aside style={{
                        width: '400px',
                        height: 'calc(100vh - 140px)',
                        position: 'sticky',
                        top: '120px',
                        backgroundColor: 'var(--color-card-bg)',
                        border: '1px solid var(--color-border-subtle)',
                        borderRadius: '20px',
                        display: 'flex',
                        flexDirection: 'column',
                        zIndex: 101,
                        animation: 'fadeIn 0.2s ease-out'
                    }}>
                        <div style={{ padding: '20px', borderBottom: '1px solid var(--color-border-subtle)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <div style={{ overflow: 'hidden' }}>
                                <h3 className="text-card-title" style={{ margin: 0, whiteSpace: 'nowrap', textOverflow: 'ellipsis', overflow: 'hidden' }}>{selectedSong.title}</h3>
                                <p className="text-overline" style={{ margin: 0 }}>{selectedSong.artist}</p>
                            </div>
                            <div style={{ display: 'flex', gap: '4px' }}>
                                <Button variant="ghost" icon="open_in_new" onClick={() => navigate(`/worship/songs/${selectedSong.id}`)} style={{ padding: '8px', minWidth: 'auto' }} />
                                <Button variant="ghost" icon="close" onClick={() => setSelectedSong(null)} style={{ padding: '8px', minWidth: 'auto' }} />
                            </div>
                        </div>

                        {/* Transpose & Mode Controls */}
                        <div style={{ padding: '12px 20px', backgroundColor: 'rgba(0,0,0,0.02)', borderBottom: '1px solid var(--color-border-subtle)', display: 'flex', flexDirection: 'column', gap: '12px' }}>
                            <div style={{ display: 'flex', backgroundColor: 'var(--color-ui-surface)', borderRadius: '8px', padding: '2px', gap: '2px' }}>
                                {['american', 'spanish', 'roman', 'lyrics'].map((m) => (
                                    <button
                                        key={m}
                                        onClick={() => setViewMode(m as any)}
                                        style={{
                                            flex: 1, padding: '6px 4px', fontSize: '10px', fontWeight: 700, border: 'none', borderRadius: '6px', cursor: 'pointer',
                                            backgroundColor: viewMode === m ? 'var(--color-brand-blue)' : 'transparent',
                                            color: viewMode === m ? 'white' : 'var(--color-ui-text-soft)',
                                            transition: 'all 0.2s'
                                        }}
                                    >
                                        {m === 'american' ? 'Am' : m === 'spanish' ? 'LA' : m === 'roman' ? 'IV' : 'TXT'}
                                    </button>
                                ))}
                            </div>

                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '4px', backgroundColor: 'var(--color-ui-surface)', padding: '4px', borderRadius: '8px' }}>
                                    <Button variant="ghost" icon="remove" onClick={() => setFontSize(p => Math.max(10, p - 2))} style={{ padding: '4px', height: '28px', minWidth: 'auto' }} />
                                    <span style={{ fontSize: '12px', fontWeight: 800, padding: '0 8px', color: 'var(--color-ui-text-soft)' }}>Tt</span>
                                    <Button variant="ghost" icon="add" onClick={() => setFontSize(p => Math.min(24, p + 2))} style={{ padding: '4px', height: '28px', minWidth: 'auto' }} />
                                </div>

                                <div style={{ display: 'flex', alignItems: 'center', gap: '4px', backgroundColor: 'var(--color-ui-surface)', padding: '4px', borderRadius: '8px' }}>
                                    <Button variant="ghost" icon="remove" onClick={() => setTranspose(p => p - 1)} style={{ padding: '4px', height: '28px', minWidth: 'auto' }} />
                                    <span style={{ fontSize: '12px', fontWeight: 800, minWidth: '40px', textAlign: 'center', color: 'var(--color-brand-blue)' }}>
                                        {musicUtils.transposeNote(selectedSong.originalKey, transpose)}
                                    </span>
                                    <Button variant="ghost" icon="add" onClick={() => setTranspose(p => p + 1)} style={{ padding: '4px', height: '28px', minWidth: 'auto' }} />
                                </div>
                            </div>
                        </div>

                        <div style={{ flex: 1, overflowY: 'auto', padding: '24px', backgroundColor: 'var(--color-ui-bg)', borderRadius: '0 0 20px 20px' }}>
                            <ChordSheetRenderer
                                content={selectedSong.content}
                                transpose={transpose}
                                viewMode={viewMode}
                                songKey={selectedSong.originalKey}
                                fontSize={fontSize}
                            />
                        </div>
                    </aside>
                </>
            )}
        </div>
    );
};

import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../../../hooks/useAuth';
import { Card } from '../../../components/ui/Card';
import { Button } from '../../../components/ui/Button';
import { Modal } from '../../../components/ui/Modal';
import { MeetingForm } from '../../../components/reunions/MeetingForm';
import { MeetingDetailView } from '../../../components/reunions/MeetingDetailView';
import api from '../../../services/api';

interface MeetingInstance {
    id: number;
    title: string;
    instance_date: string;
    start_datetime_utc: string;
    end_datetime_utc: string;
    meeting_type: 'recurrent' | 'special';
    status: 'scheduled' | 'cancelled' | 'completed';
    location: string;
    team_count: number;
    setlist_count: number;
}

export const CalendarPage: FC = () => {
    const { t, i18n } = useTranslation();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const { isMaster, user } = useAuth();
    const [instances, setInstances] = useState<MeetingInstance[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedInstanceId, setSelectedInstanceId] = useState<number | null>(null);
    const [viewMode, setViewMode] = useState<'list' | 'calendar'>('calendar');
    const [currentDate, setCurrentDate] = useState(new Date());

    const churchId = searchParams.get('church_id') ? parseInt(searchParams.get('church_id')!) : null;
    const isPastor = user?.role?.name === 'pastor';
    const finalChurchId = churchId || user?.churchId;

    useEffect(() => {
        // We no longer mandatory redirect, we just fetch if we can.
        // The UI will handle the empty/selection state.
        if (finalChurchId) {
            fetchInstances();
        } else {
            setIsLoading(false);
        }
    }, [finalChurchId, isMaster, isPastor, navigate, currentDate]);

    const fetchInstances = async () => {
        try {
            const params: { month: number; year: number; church_id?: number } = {
                month: currentDate.getMonth() + 1,
                year: currentDate.getFullYear()
            };
            if (finalChurchId) {
                params.church_id = finalChurchId;
            }

            const response = await api.get('/calendar/events', {
                params: params
            });
            // const response = await fetch(url, { // Original fetch call
            //     headers: { 'Authorization': `Bearer ${token}` }
            // });
            const data = response.data; // Assuming api service returns data directly
            if (data.success) {
                setInstances(data.instances);
            }
        } catch (err) {
            console.error('Error fetching calendar:', err);
        } finally {
            setIsLoading(false);
        }
    };

    const formatTime = (isoStr: string) => {
        const date = new Date(isoStr);
        return date.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', hour12: false });
    };

    return (
        <div style={{ position: 'relative', maxWidth: '1200px', margin: '0 auto' }}>
            <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px' }}>
                <div>
                    <h1 className="text-h1">{t('reunions.title')}</h1>
                    <p className="text-body" style={{ color: '#9CA3AF' }}>{t('reunions.description')}</p>
                </div>
                <div style={{ display: 'flex', gap: '8px' }}>
                    <div style={{
                        backgroundColor: 'rgba(255, 255, 255, 0.05)',
                        padding: '4px',
                        borderRadius: '12px',
                        display: 'flex',
                        gap: '4px',
                        border: '1px solid var(--color-border-subtle)'
                    }}>
                        <button
                            onClick={() => setViewMode('list')}
                            style={{
                                padding: '8px 16px',
                                borderRadius: '8px',
                                border: 'none',
                                cursor: 'pointer',
                                backgroundColor: viewMode === 'list' ? 'var(--color-brand-blue)' : 'transparent',
                                color: viewMode === 'list' ? 'white' : 'var(--color-ui-text-soft)',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '8px',
                                transition: 'all 0.2s'
                            }}
                        >
                            <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>list</span>
                            {t('reunions.viewList')}
                        </button>
                        <button
                            onClick={() => setViewMode('calendar')}
                            style={{
                                padding: '8px 16px',
                                borderRadius: '8px',
                                border: 'none',
                                cursor: 'pointer',
                                backgroundColor: viewMode === 'calendar' ? 'var(--color-brand-blue)' : 'transparent',
                                color: viewMode === 'calendar' ? 'white' : 'var(--color-ui-text-soft)',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '8px',
                                transition: 'all 0.2s'
                            }}
                        >
                            <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>calendar_view_month</span>
                            {t('reunions.viewCalendar')}
                        </button>
                    </div>
                    <Button label={t('reunions.newMeeting')} icon="add" onClick={() => setIsModalOpen(true)} />
                </div>
            </header>

            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title={t('reunions.newMeeting')}
            >
                <MeetingForm
                    onSuccess={() => {
                        setIsModalOpen(false);
                        fetchInstances();
                    }}
                    onCancel={() => setIsModalOpen(false)}
                />
            </Modal>

            <Modal
                isOpen={!!selectedInstanceId}
                onClose={() => setSelectedInstanceId(null)}
                title={t('reunions.details')}
            >
                {selectedInstanceId && (
                    <MeetingDetailView
                        instanceId={selectedInstanceId}
                        onClose={() => setSelectedInstanceId(null)}
                    />
                )}
            </Modal>

            {isLoading ? (
                <div className="flex-center" style={{ height: '300px' }}>
                    <div className="spinner" />
                </div>
            ) : viewMode === 'list' ? (
                <div style={{ display: 'grid', gap: '8px' }}>
                    {instances.map(instance => (
                        <Card key={instance.id} style={{ padding: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
                                <div style={{
                                    width: '60px',
                                    height: '60px',
                                    borderRadius: '16px',
                                    backgroundColor: 'rgba(59, 130, 246, 0.1)',
                                    display: 'flex',
                                    flexDirection: 'column',
                                    alignItems: 'center',
                                    justifyContent: 'center'
                                }}>
                                    <span style={{ fontSize: '10px', fontWeight: 'bold', color: 'var(--color-brand-blue)', textTransform: 'uppercase' }}>
                                        {new Date(instance.instance_date).toLocaleDateString(i18n.language, { month: 'short' })}
                                    </span>
                                    <span style={{ fontSize: '20px', fontWeight: 'bold', color: 'var(--color-brand-blue)' }}>
                                        {new Date(instance.instance_date).getDate()}
                                    </span>
                                </div>
                                <div>
                                    <h3 className="text-h3" style={{ margin: 0 }}>{instance.title}</h3>
                                    <div style={{ display: 'flex', gap: '12px', color: '#6B7280', fontSize: '14px', marginTop: '4px' }}>
                                        <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                                            <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>schedule</span>
                                            {formatTime(instance.start_datetime_utc)}
                                        </span>
                                        {instance.location && (
                                            <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                                                <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>location_on</span>
                                                {instance.location}
                                            </span>
                                        )}
                                        <span className={`status-badge ${instance.meeting_type === 'recurrent' ? 'status-active' : 'status-pending'}`} style={{ fontSize: '10px' }}>
                                            {instance.meeting_type === 'recurrent' ? t('reunions.status.recurrent') : t('reunions.status.special')}
                                        </span>
                                    </div>
                                </div>
                            </div>

                            <div style={{ display: 'flex', gap: '24px', alignItems: 'center' }}>
                                <div style={{ textAlign: 'center' }}>
                                    <p className="text-overline" style={{ color: instance.team_count > 0 ? '#10B981' : '#F59E0B' }}>
                                        {instance.team_count > 0 ? t('reunions.status.withTeam') : t('reunions.status.noTeam')}
                                    </p>
                                    <p className="text-body" style={{ fontSize: '12px', margin: 0 }}>{t('reunions.assignedMembers', { count: instance.team_count })}</p>
                                </div>
                                <div style={{ textAlign: 'center' }}>
                                    <p className="text-overline" style={{ color: instance.setlist_count > 0 ? '#10B981' : '#F59E0B' }}>
                                        {instance.setlist_count > 0 ? t('reunions.status.withSetlist') : t('reunions.status.noSetlist')}
                                    </p>
                                    <p className="text-body" style={{ fontSize: '12px', margin: 0 }}>{t('reunions.songCount', { count: instance.setlist_count })}</p>
                                </div>
                                <Button variant="secondary" icon="chevron_right" onClick={() => setSelectedInstanceId(instance.id)} />
                            </div>
                        </Card>
                    ))}

                    {instances.length === 0 && (
                        <div style={{ textAlign: 'center', padding: '60px', opacity: 0.8, backgroundColor: 'var(--color-ui-surface)', borderRadius: '24px', border: '1px dashed var(--color-border-subtle)' }}>
                            <span className="material-symbols-outlined" style={{ fontSize: '48px', color: 'var(--color-brand-blue)', marginBottom: '16px' }}>
                                {!finalChurchId ? 'account_balance' : 'calendar_today'}
                            </span>
                            <p className="text-h3" style={{ marginBottom: '8px' }}>
                                {!finalChurchId ? 'No hay iglesia seleccionada' : t('reunions.noMeetings')}
                            </p>
                            <p className="text-body" style={{ color: 'var(--color-ui-text-soft)', marginBottom: '24px' }}>
                                {!finalChurchId ? 'Selecciona una iglesia para ver su calendario de actividades.' : 'No hay eventos programados para este mes.'}
                            </p>
                            {!finalChurchId && (isMaster || isPastor) && (
                                <Button
                                    label="Seleccionar Iglesia"
                                    variant="primary"
                                    onClick={() => navigate('/mainhub/select-church/calendar')}
                                    style={{ margin: '0 auto' }}
                                />
                            )}
                        </div>
                    )}
                </div>
            ) : (
                <div style={{ animation: 'fadeIn 0.3s ease-out' }}>
                    {/* Monthly Navigation */}
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                        <h2 className="text-h2" style={{ textTransform: 'capitalize' }}>
                            {currentDate.toLocaleDateString(i18n.language, { month: 'long', year: 'numeric' })}
                        </h2>
                        <div style={{ display: 'flex', gap: '8px' }}>
                            <Button
                                variant="secondary"
                                icon="chevron_left"
                                onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))}
                            />
                            <Button
                                variant="secondary"
                                label={t('reunions.today')}
                                onClick={() => setCurrentDate(new Date())}
                            />
                            <Button
                                variant="secondary"
                                icon="chevron_right"
                                onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))}
                            />
                        </div>
                    </div>

                    <Card style={{ padding: '0', overflow: 'hidden' }}>
                        {/* Weekday Headers */}
                        <div style={{
                            display: 'grid',
                            gridTemplateColumns: 'repeat(7, 1fr)',
                            backgroundColor: 'rgba(255, 255, 255, 0.03)',
                            borderBottom: '1px solid var(--color-border-subtle)'
                        }}>
                            {(() => {
                                const weekDays = [
                                    t('days.1').substring(0, 3), // Monday
                                    t('days.2').substring(0, 3), // Tuesday
                                    t('days.3').substring(0, 3), // Wednesday
                                    t('days.4').substring(0, 3), // Thursday
                                    t('days.5').substring(0, 3), // Friday
                                    t('days.6').substring(0, 3), // Saturday
                                    t('days.0').substring(0, 3)  // Sunday
                                ];
                                return weekDays.map(day => (
                                    <div key={day} style={{ padding: '12px', textAlign: 'center' }}>
                                        <span className="text-overline" style={{ color: 'var(--color-ui-text-soft)' }}>{day}</span>
                                    </div>
                                ));
                            })()}
                        </div>

                        {/* Calendar Grid */}
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)' }}>
                            {(() => {
                                const year = currentDate.getFullYear();
                                const month = currentDate.getMonth();
                                const firstDayOfMonth = new Date(year, month, 1);
                                const lastDayOfMonth = new Date(year, month + 1, 0);

                                // Adjust to start on Monday (JS Date: 0=Sun, 1=Mon... -> adjustment: (day+6)%7)
                                const firstDayIndex = (firstDayOfMonth.getDay() + 6) % 7;
                                const totalDays = lastDayOfMonth.getDate();

                                const days = [];
                                // Padding from previous month
                                const prevMonthLastDay = new Date(year, month, 0).getDate();
                                for (let i = firstDayIndex - 1; i >= 0; i--) {
                                    days.push({ day: prevMonthLastDay - i, currentMonth: false, date: new Date(year, month - 1, prevMonthLastDay - i) });
                                }
                                // Days of current month
                                for (let i = 1; i <= totalDays; i++) {
                                    days.push({ day: i, currentMonth: true, date: new Date(year, month, i) });
                                }
                                // Padding from next month
                                const remainingRows = Math.ceil(days.length / 7);
                                const totalCells = remainingRows * 7;
                                const nextMonthPadding = totalCells - days.length;
                                for (let i = 1; i <= nextMonthPadding; i++) {
                                    days.push({ day: i, currentMonth: false, date: new Date(year, month + 1, i) });
                                }

                                return days.map((dayObj, idx) => {
                                    // Find events for this day
                                    // We need to compare dates. Since instance_date is YYYY-MM-DD
                                    const dayStr = dayObj.date.toISOString().split('T')[0];
                                    const dayEvents = instances.filter(inst => inst.instance_date === dayStr);

                                    return (
                                        <div
                                            key={idx}
                                            style={{
                                                minHeight: '120px',
                                                borderRight: idx % 7 === 6 ? 'none' : '1px solid var(--color-border-subtle)',
                                                borderBottom: idx >= totalCells - 7 ? 'none' : '1px solid var(--color-border-subtle)',
                                                padding: '8px',
                                                backgroundColor: dayObj.currentMonth ? 'transparent' : 'rgba(255, 255, 255, 0.02)',
                                                display: 'flex',
                                                flexDirection: 'column',
                                                gap: '4px'
                                            }}
                                        >
                                            <span style={{
                                                fontSize: '12px',
                                                fontWeight: dayObj.currentMonth ? '600' : '400',
                                                opacity: dayObj.currentMonth ? 1 : 0.5,
                                                marginBottom: '4px',
                                                display: 'flex',
                                                justifyContent: 'center',
                                                alignItems: 'center',
                                                width: '24px',
                                                height: '24px',
                                                borderRadius: '50%',
                                                backgroundColor: dayStr === new Date().toISOString().split('T')[0] ? 'var(--color-brand-blue)' : 'transparent',
                                                color: dayStr === new Date().toISOString().split('T')[0] ? 'white' : (dayObj.currentMonth ? 'var(--color-ui-text)' : 'var(--color-ui-text-soft)')
                                            }}>
                                                {dayObj.day}
                                            </span>

                                            <div style={{ display: 'flex', flexDirection: 'column', gap: '2px', overflowY: 'auto', maxHeight: '80px' }}>
                                                {dayEvents.map(event => (
                                                    <div
                                                        key={event.id}
                                                        onClick={() => setSelectedInstanceId(event.id)}
                                                        style={{
                                                            fontSize: '10px',
                                                            padding: '4px 6px',
                                                            borderRadius: '6px',
                                                            backgroundColor: event.meeting_type === 'recurrent' ? 'rgba(59, 130, 246, 0.15)' : 'rgba(245, 158, 11, 0.15)',
                                                            color: event.meeting_type === 'recurrent' ? '#3B82F6' : '#F59E0B',
                                                            whiteSpace: 'nowrap',
                                                            overflow: 'hidden',
                                                            textOverflow: 'ellipsis',
                                                            cursor: 'pointer',
                                                            borderLeft: `3px solid ${event.meeting_type === 'recurrent' ? '#3B82F6' : '#F59E0B'}`,
                                                            transition: 'transform 0.1s'
                                                        }}
                                                        title={`${formatTime(event.start_datetime_utc)} - ${event.title}`}
                                                    >
                                                        <b>{formatTime(event.start_datetime_utc)}</b> {event.title}
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    );
                                });
                            })()}
                        </div>
                    </Card>
                </div>
            )}
        </div>
    );
};

import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { Card } from '../components/ui/Card';
import { Button } from '../components/ui/Button';

export const AcceptInvite: FC = () => {
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const token = searchParams.get('token');

    const [isLoading, setIsLoading] = useState(true);
    const [invitation, setInvitation] = useState<any>(null);
    const [error, setError] = useState<string | null>(null);
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [success, setSuccess] = useState(false);

    useEffect(() => {
        if (!token) {
            setError('Falta el token de invitaci├│n.');
            setIsLoading(false);
            return;
        }

        verifyToken();
    }, [token]);

    const verifyToken = async () => {
        try {
            const response = await fetch(`/api/auth/verify-invite?token=${token}`);
            if (!response.ok) {
                const errorText = await response.text();
                console.error(`API Error (${response.status}):`, errorText);
                setError(`Error de servidor (${response.status}). Por favor, contacte a soporte.`);
                setIsLoading(false);
                return;
            }
            const data = await response.json();
            if (data.success) {
                setInvitation(data.invitation);
            } else {
                setError(data.error || 'La invitaci├│n no es v├ílida.');
            }
        } catch (err) {
            setError('Error al verificar la invitaci├│n.');
        } finally {
            setIsLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (password !== confirmPassword) {
            setError('Las contrase├▒as no coinciden.');
            return;
        }
        if (password.length < 6) {
            setError('La contrase├▒a debe tener al menos 6 caracteres.');
            return;
        }

        setIsSubmitting(true);
        setError(null);

        try {
            const response = await fetch('/api/auth/accept-invite', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ token, password })
            });
            const data = await response.json();
            if (data.success) {
                // Auto-login: Store token and user
                localStorage.setItem('auth_token', data.token);

                setSuccess(true);
                // The App will reload bootstrap on the next page since we changed localStorage
                setTimeout(() => {
                    window.location.href = '/join-teams';
                }, 1500);
            } else {
                setError(data.error || 'No se pudo completar el registro.');
            }
        } catch (err) {
            setError('Error de conexi├│n.');
        } finally {
            setIsSubmitting(false);
        }
    };

    if (isLoading) {
        return (
            <div className="flex-center" style={{ height: '100vh', backgroundColor: 'var(--color-ui-bg)' }}>
                <p className="text-body" style={{ color: 'var(--color-ui-text)' }}>Verificando invitaci├│n...</p>
            </div>
        );
    }

    if (success) {
        return (
            <div className="flex-center" style={{ height: '100vh', backgroundColor: 'var(--color-ui-bg)', padding: '24px' }}>
                <Card style={{ maxWidth: '400px', textAlign: 'center', padding: '32px' }}>
                    <span className="material-symbols-outlined" style={{ color: 'var(--color-brand-blue)', fontSize: '48px', marginBottom: '16px' }}>check_circle</span>
                    <h1 className="text-h1">┬íRegistro Completado!</h1>
                    <p className="text-body" style={{ color: '#9CA3AF', marginTop: '16px' }}>
                        Tu cuenta ha sido activada con ├®xito. Ser├ís redirigido en unos segundos...
                    </p>
                </Card>
            </div>
        );
    }

    return (
        <div className="flex-center" style={{ minHeight: '100vh', backgroundColor: 'var(--color-ui-bg)', padding: '24px' }}>
            <Card style={{ maxWidth: '440px', width: '100%', padding: '32px' }}>
                <header style={{ textAlign: 'center', marginBottom: '32px' }}>
                    <div style={{
                        width: '56px', height: '56px', borderRadius: '50%', backgroundColor: 'var(--color-brand-blue)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px'
                    }}>
                        <span className="material-symbols-outlined" style={{ color: 'white' }}>church</span>
                    </div>
                    <h1 className="text-h1">{invitation?.church || 'Bienvenido'}</h1>
                    {invitation && (
                        <p className="text-body" style={{ color: '#9CA3AF', marginTop: '8px' }}>
                            Hola <strong>{invitation.name}</strong>, configur├í tu acceso para comenzar.
                        </p>
                    )}
                </header>

                {error ? (
                    <div style={{ textAlign: 'center' }}>
                        <div style={{
                            padding: '16px', borderRadius: '12px', backgroundColor: 'rgba(239, 68, 68, 0.1)',
                            color: '#EF4444', marginBottom: '24px', fontSize: '14px'
                        }}>
                            {error}
                        </div>
                        <Button label="Volver al Inicio" onClick={() => navigate('/login')} variant="ghost" style={{ width: '100%' }} />
                    </div>
                ) : (
                    <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                        <div>
                            <label className="text-overline" style={{ display: 'block', marginBottom: '8px', color: '#6B7280' }}>NUEVA CONTRASE├æA</label>
                            <input
                                type="password"
                                required
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                style={{
                                    width: '100%', padding: '12px 16px', borderRadius: '12px', border: '1px solid var(--color-border-subtle)',
                                    backgroundColor: 'var(--color-ui-surface)', color: 'var(--color-ui-text)', outline: 'none'
                                }}
                            />
                        </div>
                        <div>
                            <label className="text-overline" style={{ display: 'block', marginBottom: '8px', color: '#6B7280' }}>CONFIRMAR CONTRASE├æA</label>
                            <input
                                type="password"
                                required
                                value={confirmPassword}
                                onChange={(e) => setConfirmPassword(e.target.value)}
                                style={{
                                    width: '100%', padding: '12px 16px', borderRadius: '12px', border: '1px solid var(--color-border-subtle)',
                                    backgroundColor: 'var(--color-ui-surface)', color: 'var(--color-ui-text)', outline: 'none'
                                }}
                            />
                        </div>

                        <Button
                            type="submit"
                            variant="primary"
                            label={isSubmitting ? "Completando..." : "Activar Cuenta"}
                            disabled={isSubmitting}
                            style={{ marginTop: '12px', padding: '14px' }}
                        />
                    </form>
                )}

                <footer style={{ marginTop: '32px', textAlign: 'center' }}>
                    <p className="text-overline" style={{ color: '#4B5563' }}>
                        ┬® {new Date().getFullYear()} MinistryHub<br />
                        Plataforma de Gesti├│n Ministerial
                    </p>
                </footer>
            </Card>
        </div>
    );
};

import type { FC, FormEvent } from 'react';
import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Link } from 'react-router-dom';
import { Card } from '../components/ui/Card';
import { Button } from '../components/ui/Button';

export const ForgotPassword: FC = () => {
    const { t } = useTranslation();
    const [email, setEmail] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

    const handleSubmit = async (e: FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setMessage(null);

        try {
            const response = await fetch('/api/auth/forgot-password', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email })
            });
            const data = await response.json();

            if (data.success) {
                setMessage({ type: 'success', text: data.message });
            } else {
                setMessage({ type: 'error', text: data.error || t('auth.resetError') });
            }
        } catch (err) {
            setMessage({ type: 'error', text: t('common.connectionError') });
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div style={{
            display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
            minHeight: '100vh', padding: '24px', backgroundColor: 'var(--color-ui-surface)'
        }}>
            <div style={{ marginBottom: '32px', textAlign: 'center' }}>
                <span className="material-symbols-outlined" style={{ fontSize: '48px', color: 'var(--color-brand-blue)' }}>lock_reset</span>
                <h1 className="text-h1" style={{ marginTop: '16px' }}>{t('auth.forgotPasswordTitle')}</h1>
                <p className="text-body" style={{ color: '#6B7280' }}>{t('auth.forgotPasswordSubtitle')}</p>
            </div>

            <Card style={{ padding: '32px', width: '100%', maxWidth: '400px' }}>
                <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                    {message && (
                        <div style={{
                            padding: '12px',
                            backgroundColor: message.type === 'success' ? 'rgba(16, 185, 129, 0.1)' : 'rgba(239, 68, 68, 0.1)',
                            color: message.type === 'success' ? '#10B981' : '#EF4444',
                            borderRadius: '12px', fontSize: '14px', textAlign: 'center'
                        }}>
                            {message.text}
                        </div>
                    )}

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        <label className="text-overline" style={{ color: '#6B7280' }}>{t('auth.email')}</label>
                        <input
                            type="email"
                            placeholder={t('auth.emailPlaceholder')}
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                            className="w-full"
                        />
                    </div>

                    <Button
                        type="submit"
                        label={isLoading ? t('common.sending') : t('auth.sendLink')}
                        variant="primary"
                        disabled={isLoading}
                        style={{ width: '100%', marginTop: '8px' }}
                    />
                </form>

                <div style={{ marginTop: '24px', textAlign: 'center' }}>
                    <Link to="/login" style={{ color: 'var(--color-brand-blue)', fontWeight: 600, textDecoration: 'none', fontSize: '14px' }}>
                        {t('auth.backToLogin')}
                    </Link>
                </div>
            </Card>
        </div>
    );
};

import { useState, useEffect, type FC } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { Card } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { useToast } from '../context/ToastContext';
import { invitationService } from '../services/invitationService';
import type { InvitationTemplate } from '../services/invitationService';

export const InvitationSettings: FC = () => {
    const { church, isMaster, hasRole } = useAuth();
    const navigate = useNavigate();
    const { addToast } = useToast();

    const [templates, setTemplates] = useState<InvitationTemplate[]>([]);
    const [selectedIndex, setSelectedIndex] = useState(0);
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);

    // Editor state
    const [subject, setSubject] = useState('');
    const [body, setBody] = useState('');
    const [isActive, setIsActive] = useState(false);

    const canEdit = isMaster || hasRole('pastor') || hasRole('leader') || hasRole('coordinator');

    useEffect(() => {
        if (!canEdit) {
            addToast('No tienes permisos para editar plantillas', 'error');
            navigate('/settings');
            return;
        }
        loadTemplates();
    }, [church?.id]);

    const loadTemplates = async () => {
        if (!church?.id) return;
        setIsLoading(true);
        try {
            const data = await invitationService.getTemplates(church.id);
            setTemplates(data);

            // Load selected template into editor
            const current = data.find(t => t.template_index === selectedIndex);
            if (current) {
                setSubject(current.subject);
                setBody(current.body_html);
                setIsActive(current.is_active);
            } else {
                // Default values if not found
                setSubject(`Invitaci├│n a formar parte de ${church.name}`);
                setBody('Hola {{USER_NAME}}, \n\nHas sido invitado a formar parte del equipo en {{CHURCH_NAME}}. \n\nEntra aqu├¡ para registrarte: {{INVITE_URL}}');
                setIsActive(false);
            }
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        const current = templates.find(t => t.template_index === selectedIndex);
        if (current) {
            setSubject(current.subject);
            setBody(current.body_html);
            setIsActive(current.is_active);
        } else {
            setSubject(`Invitaci├│n a formar parte de ${church?.name || ''}`);
            setBody('Hola {{USER_NAME}}, \n\nHas sido invitado a formar parte del equipo en {{CHURCH_NAME}}. \n\nEntra aqu├¡ para registrarte: {{INVITE_URL}}');
            setIsActive(false);
        }
    }, [selectedIndex, templates]);

    const handleSave = async () => {
        if (!church?.id) return;
        setIsSaving(true);
        try {
            const success = await invitationService.saveTemplate({
                church_id: church.id,
                template_index: selectedIndex,
                is_active: isActive,
                subject,
                body_html: body
            });

            if (success) {
                addToast('Plantilla guardada correctamente', 'success');
                loadTemplates();
            } else {
                addToast('Error al guardar la plantilla', 'error');
            }
        } finally {
            setIsSaving(false);
        }
    };

    if (isLoading) return <div style={{ padding: '20px', textAlign: 'center' }}>Cargando...</div>;

    const Placeholder = ({ name }: { name: string }) => (
        <code style={{
            backgroundColor: 'var(--color-ui-bg)',
            padding: '2px 6px',
            borderRadius: '4px',
            color: 'var(--color-brand-blue)',
            fontSize: 'var(--font-size-xs)'
        }}>{`{{${name}}}`}</code>
    );

    return (
        <div style={{ maxWidth: '800px', margin: '0 auto', paddingBottom: '40px' }}>
            <header style={{ marginBottom: '24px', display: 'flex', alignItems: 'center', gap: '12px' }}>
                <Button variant="ghost" icon="arrow_back" onClick={() => navigate('/settings')} />
                <div>
                    <h1 className="text-h1">Plantillas de Invitaci├│n</h1>
                    <p className="text-body-secondary">Personaliza los correos que env├¡as a tu equipo.</p>
                </div>
            </header>

            <section style={{ marginBottom: '32px' }}>
                <h3 className="text-overline" style={{ marginBottom: '12px' }}>Seleccionar Plantilla</h3>
                <div style={{ display: 'flex', gap: '12px' }}>
                    {[0, 1, 2].map(idx => {
                        const tpl = templates.find(t => t.template_index === idx);
                        const activeLabel = tpl?.is_active ? ' (En uso)' : '';
                        return (
                            <Card
                                key={idx}
                                onClick={() => setSelectedIndex(idx)}
                                style={{
                                    flex: 1,
                                    padding: '16px',
                                    textAlign: 'center',
                                    cursor: 'pointer',
                                    border: selectedIndex === idx ? '2px solid var(--color-brand-blue)' : '1px solid var(--color-border-subtle)',
                                    backgroundColor: selectedIndex === idx ? 'var(--color-brand-blue-transparent)' : 'var(--color-ui-card-bg)'
                                }}
                            >
                                <span className="material-symbols-outlined" style={{ fontSize: '32px', marginBottom: '8px', opacity: 0.5 }}>drafts</span>
                                <p style={{ margin: 0, fontWeight: 600 }}>Variante {idx + 1}{activeLabel}</p>
                            </Card>
                        );
                    })}
                </div>
            </section>

            <Card style={{ padding: '24px' }}>
                <div style={{ marginBottom: '20px' }}>
                    <label style={{ display: 'block', fontWeight: 600, marginBottom: '8px' }}>Asunto del Correo</label>
                    <input
                        type="text"
                        value={subject}
                        onChange={(e) => setSubject(e.target.value)}
                        placeholder="Escribe el asunto..."
                        style={{
                            width: '100%',
                            padding: '12px',
                            borderRadius: '8px',
                            border: '1px solid var(--color-border-subtle)',
                            backgroundColor: 'var(--color-ui-bg)',
                            color: 'var(--color-ui-text)'
                        }}
                    />
                </div>

                <div style={{ marginBottom: '20px' }}>
                    <label style={{ display: 'block', fontWeight: 600, marginBottom: '8px' }}>Cuerpo del Mensaje (HTML compatible)</label>
                    <textarea
                        value={body}
                        onChange={(e) => setBody(e.target.value)}
                        placeholder="Escribe el contenido..."
                        style={{
                            width: '100%',
                            minHeight: '300px',
                            padding: '12px',
                            borderRadius: '8px',
                            border: '1px solid var(--color-border-subtle)',
                            backgroundColor: 'var(--color-ui-bg)',
                            color: 'var(--color-ui-text)',
                            fontFamily: 'monospace'
                        }}
                    />
                </div>

                <div style={{
                    padding: '16px',
                    borderRadius: '12px',
                    backgroundColor: 'var(--color-ui-bg-soft)',
                    marginBottom: '24px',
                    border: '1px dashed var(--color-border-subtle)'
                }}>
                    <p style={{ margin: '0 0 12px 0', fontSize: 'var(--font-size-sm)', fontWeight: 600 }}>Variables disponibles:</p>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                        <Placeholder name="USER_NAME" />
                        <Placeholder name="CHURCH_NAME" />
                        <Placeholder name="ROLE_NAME" />
                        <Placeholder name="ROLE_LOWER" />
                        <Placeholder name="INVITE_URL" />
                    </div>
                </div>

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <label style={{ display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer' }}>
                        <input
                            type="checkbox"
                            checked={isActive}
                            onChange={(e) => setIsActive(e.target.checked)}
                            style={{ width: '20px', height: '20px' }}
                        />
                        <span style={{ fontWeight: 600 }}>Usar esta versi├│n para nuevas invitaciones</span>
                    </label>

                    <Button
                        disabled={isSaving}
                        onClick={handleSave}
                        variant="primary"
                    >
                        {isSaving ? 'Guardando...' : 'Guardar Plantilla'}
                    </Button>
                </div>
            </Card>
        </div>
    );
};

import type { FC } from 'react';
import { useState, useEffect } from 'react';
import { Card } from '../components/ui/Card';
import { Button } from '../components/ui/Button';

export const LiveDebug: FC = () => {
    const [logs, setLogs] = useState<string>('');
    const [isLoading, setIsLoading] = useState(true);
    const [autoRefresh, setAutoRefresh] = useState(true);

    const fetchLogs = async () => {
        try {
            const token = localStorage.getItem('auth_token');
            const response = await fetch('/api/debug.php', {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await response.json();
            if (data.success) {
                setLogs(data.logs);
            }
        } catch (err) {
            console.error('Error fetching logs:', err);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchLogs();
        let interval: any;
        if (autoRefresh) {
            interval = setInterval(fetchLogs, 3000);
        }
        return () => clearInterval(interval);
    }, [autoRefresh]);

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '8px' }}>
                <div>
                    <h1 className="text-h1">Consola de Debug</h1>
                    <p className="text-body" style={{ color: '#9CA3AF' }}>Monitoreo en vivo del sistema (Producci├│n)</p>
                </div>
                <div style={{ display: 'flex', gap: '12px' }}>
                    <Button
                        variant={autoRefresh ? 'primary' : 'secondary'}
                        label={autoRefresh ? 'Auto-refresh ON' : 'Auto-refresh OFF'}
                        onClick={() => setAutoRefresh(!autoRefresh)}
                    />
                    <Button variant="secondary" label="Limpiar Pantalla" onClick={() => setLogs('')} />
                </div>
            </header>

            <Card style={{
                backgroundColor: '#0F172A',
                padding: '16px',
                borderRadius: '12px',
                border: '1px solid #1E293B',
                minHeight: '400px',
                display: 'flex',
                flexDirection: 'column'
            }}>
                <div style={{
                    fontFamily: 'monospace',
                    fontSize: '13px',
                    color: '#38BDF8',
                    overflowY: 'auto',
                    flex: 1,
                    whiteSpace: 'pre-wrap',
                    lineHeight: '1.6'
                }}>
                    {isLoading ? 'Cargando logs...' : logs || 'No hay logs recientes.'}
                </div>
            </Card>

            <div className="flex-center" style={{ gap: '12px', color: '#6B7280' }}>
                <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>info</span>
                <p className="text-overline">Este archivo se guarda f├¡sicamente en la ra├¡z como msm_debug.log</p>
            </div>
        </div>
    );
};

import type { FC, FormEvent } from 'react';
import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate, Link, useSearchParams } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { Card } from '../components/ui/Card';
import { Button } from '../components/ui/Button';

export const Login: FC = () => {
    const { t } = useTranslation();
    const { login, isAuthenticated } = useAuth();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(searchParams.get('error'));

    useEffect(() => {
        if (isAuthenticated) {
            navigate('/dashboard', { replace: true });
        }
    }, [isAuthenticated, navigate]);

    const handleSubmit = async (e: FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError(null);
        try {
            // Skip reCAPTCHA for now due to 401/403 errors
            const recaptchaToken = '';
            /*
            const recaptchaToken = await new Promise<string>((resolve) => {
                if (!(window as any).grecaptcha) {
                    console.error('reCAPTCHA not loaded');
                    resolve('');
                    return;
                }
                (window as any).grecaptcha.ready(() => {
                    (window as any).grecaptcha.execute('6Lf3pnwsAAAAANJfrY5MQDh8BogqHziLeosV9Rnw', { action: 'login' })
                        .then((token: string) => resolve(token))
                        .catch((err: any) => {
                            console.error('reCAPTCHA execution failed', err);
                            resolve('');
                        });
                });
            });
            */

            await login(email, password, recaptchaToken);
        } catch (err: any) {
            console.error('Login error details:', err);
            const detail = err.response?.data?.error || err.response?.data?.message || err.message;
            setError(detail);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            minHeight: '100vh',
            padding: '24px',
            backgroundColor: 'var(--color-ui-surface)'
        }}>
            <div style={{ marginBottom: '32px', textAlign: 'center' }}>
                <span className="material-symbols-outlined" style={{ fontSize: '48px', color: 'var(--color-brand-blue)' }}>church</span>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', marginTop: '16px' }}>
                    <h1 className="text-h1">{t('auth.signInTitle', { church: t('common.church') })}</h1>
                    <span style={{
                        fontSize: '10px',
                        fontWeight: 700,
                        textTransform: 'uppercase',
                        padding: '2px 6px',
                        borderRadius: '6px',
                        backgroundColor: 'rgba(59, 130, 246, 0.1)',
                        color: 'var(--color-brand-blue)',
                        border: '1px solid rgba(59, 130, 246, 0.2)',
                        letterSpacing: '0.05em',
                        lineHeight: 1
                    }}>
                        Beta
                    </span>
                </div>
                <p className="text-body" style={{ color: '#6B7280' }}>{t('auth.signInSubtitle')}</p>
            </div>

            <Card style={{ padding: '32px', width: '100%', maxWidth: '400px' }}>
                <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>

                    {error && (
                        <div style={{
                            padding: '12px',
                            backgroundColor: 'rgba(239, 68, 68, 0.1)',
                            color: '#EF4444',
                            borderRadius: '12px',
                            fontSize: '14px',
                            textAlign: 'center'
                        }}>
                            {error}
                        </div>
                    )}

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        <label className="text-overline" style={{ color: '#6B7280' }}>{t('auth.email')}</label>
                        <input
                            type="email"
                            placeholder={t('auth.emailPlaceholder')}
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                            className="w-full"
                        />
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <label className="text-overline" style={{ color: '#6B7280' }}>{t('auth.password')}</label>
                            <Link to="/forgot-password" style={{ fontSize: '12px', color: 'var(--color-brand-blue)', textDecoration: 'none', fontWeight: 500 }}>
                                {t('auth.forgotPassword') || '┬┐Olvidaste tu contrase├▒a?'}
                            </Link>
                        </div>
                        <div style={{ position: 'relative' }}>
                            <input
                                type={showPassword ? "text" : "password"}
                                placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                                className="w-full"
                                style={{ paddingRight: '48px' }}
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                style={{
                                    position: 'absolute',
                                    right: '12px',
                                    top: '50%',
                                    transform: 'translateY(-50%)',
                                    background: 'none',
                                    border: 'none',
                                    color: '#6B7280',
                                    cursor: 'pointer',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    padding: '4px'
                                }}
                            >
                                <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
                                    {showPassword ? 'visibility_off' : 'visibility'}
                                </span>
                            </button>
                        </div>
                    </div>

                    <Button
                        type="submit"
                        label={isLoading ? t('auth.signingIn') : t('auth.signInAction')}
                        variant="primary"
                        disabled={isLoading}
                        style={{ width: '100%', marginTop: '8px' }}
                    />
                </form>

                <div style={{ margin: '24px 0', display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <div style={{ flex: 1, height: '1px', backgroundColor: 'var(--color-border-subtle)' }} />
                    <span className="text-overline" style={{ color: '#6B7280' }}>O CONTINUAR CON</span>
                    <div style={{ flex: 1, height: '1px', backgroundColor: 'var(--color-border-subtle)' }} />
                </div>

                <Button
                    onClick={() => {
                        document.cookie = "msm_google_mode=login; path=/; max-age=600";
                        const redirectUri = encodeURIComponent(`${window.location.origin}/api/auth/google/callback`);
                        window.location.href = `https://accounts.google.com/o/oauth2/v2/auth?client_id=${import.meta.env.VITE_GOOGLE_CLIENT_ID}&redirect_uri=${redirectUri}&response_type=code&scope=email%20profile`;
                    }}
                    variant="ghost"
                    style={{
                        width: '100%',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        gap: '12px',
                        border: '1px solid var(--color-border-subtle)',
                        borderRadius: '12px',
                        backgroundColor: 'var(--color-ui-bg)'
                    }}
                >
                    <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" alt="Google" style={{ width: '18px', height: '18px' }} />
                    <span className="text-body" style={{ fontWeight: 500 }}>Continuar con Google</span>
                </Button>
            </Card>

            <div style={{ marginTop: '24px', textAlign: 'center', maxWidth: '300px' }}>
                <p style={{ fontSize: '11px', color: '#9CA3AF', lineHeight: '1.4' }}>
                    Protegido por reCAPTCHA. <br />
                    <a href="https://google.com/intl/es/policies/privacy" target="_blank" rel="noreferrer" style={{ color: 'var(--color-brand-blue)', textDecoration: 'none' }}>Privacidad</a> y <a href="https://google.com/intl/es/policies/terms" target="_blank" rel="noreferrer" style={{ color: 'var(--color-brand-blue)', textDecoration: 'none' }}>T├®rminos</a> de Google.
                </p>
            </div>
        </div>
    );
};

import type { FC } from 'react';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../hooks/useAuth';
import { Card } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { useEffect, useState } from 'react';
import { songService } from '../services/songService';
import { peopleService } from '../services/peopleService';
import { ActivityFeed } from '../components/dashboard/ActivityFeed';
import { MasterDashboard } from '../modules/mainhub/pages/MasterDashboard';
import { PastorDashboard } from '../modules/mainhub/pages/PastorDashboard';
import { Playlists } from '../modules/worship/pages/Playlists';
import { Reports } from '../modules/mainhub/pages/Reports';
import { useProfileCompletion } from '../hooks/useProfileCompletion';

export const MainDashboard: FC = () => {
    const { t } = useTranslation();
    const { user } = useAuth();
    const navigate = useNavigate();
    useProfileCompletion();
    const [pendingCount, setPendingCount] = useState(0);
    const [pendingMembers, setPendingMembers] = useState(0);
    const [groups, setGroups] = useState<any[]>([]);
    const [requestingId, setRequestingId] = useState<number | null>(null);

    const isGuest = user?.role?.level === 200;
    const isLeader = (user?.role?.level || 100) <= 50;

    const isMaster = user?.isMaster || user?.role?.name === 'master' || user?.role?.name === 'superadmin';
    const isPastor = user?.role?.name === 'pastor';
    const isMember = user?.role?.name === 'member' || (!isPastor && !isMaster && !isLeader && !isGuest);

    useEffect(() => {
        if (isLeader) {
            songService.getPendingEdits().then(edits => setPendingCount(edits.length));
        }
        if (isMaster || isPastor) {
            peopleService.getAll().then(users => {
                if (Array.isArray(users)) {
                    const pending = users.filter((u: any) => u.status === 'pending');
                    setPendingMembers(pending.length);
                }
            });
        }
        if (isGuest) {
            peopleService.getGroups().then(setGroups);
        }
    }, [user, isLeader, isGuest, isMaster, isPastor]);

    const handleRequestJoin = (groupId: number) => {
        setRequestingId(groupId);
        setTimeout(() => {
            setRequestingId(null);
            alert(t('dashboard.requestSent'));
        }, 1000);
    };

    // Role-based HOME selection
    if (isMaster) return <MasterDashboard />;
    if (isPastor) return <Reports />;
    if (isMember) return <Playlists />;

    if (isGuest) {
        return (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
                <header>
                    <h1 className="text-h1" style={{ marginBottom: '8px' }}>
                        {t('dashboard.welcome', { name: user?.name })}
                    </h1>
                    <Card style={{ backgroundColor: 'var(--color-brand-blue-light)', border: '1px solid var(--color-brand-blue)' }}>
                        <p className="text-body" style={{ color: 'var(--color-brand-blue)', fontWeight: 500 }}>
                            {t('people.moderation.pendingApproval')}
                        </p>
                    </Card>
                </header>

                <section>
                    <h2 className="text-h2" style={{ marginBottom: '16px' }}>{t('dashboard.availableTeams')}</h2>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        {groups.length === 0 ? (
                            <p className="text-body" style={{ color: 'gray' }}>{t('dashboard.loadingTeams')}</p>
                        ) : (
                            groups.map(group => (
                                <Card key={group.id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <div>
                                        <p className="text-card-title">{group.name}</p>
                                        <p className="text-overline" style={{ color: 'gray' }}>{group.description || t('dashboard.noDescription')}</p>
                                    </div>
                                    <Button
                                        label={requestingId === group.id ? t('dashboard.requesting') : t('dashboard.requestJoin')}
                                        variant="secondary"
                                        disabled={requestingId !== null}
                                        onClick={() => handleRequestJoin(group.id)}
                                    />
                                </Card>
                            ))
                        )}
                    </div>
                </section>

                <section>
                    <Card style={{ backgroundColor: 'var(--color-ui-surface)', textAlign: 'center', padding: '24px' }}>
                        <span className="material-symbols-outlined" style={{ fontSize: '48px', color: 'gray', marginBottom: '12px' }}>info</span>
                        <p className="text-body" style={{ color: 'gray', margin: 0 }}>
                            {t('dashboard.waitingNotice')}
                        </p>
                    </Card>
                </section>
            </div>
        );
    }

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
            {isMaster && <MasterDashboard />}
            {isPastor && <PastorDashboard />}

            {!isMaster && !isPastor && (
                <>
                    <header>
                        <h1 className="text-h1" style={{ marginBottom: '4px' }}>
                            {t('dashboard.welcome', { name: user?.name || '' })}
                        </h1>
                        <p className="text-body" style={{ color: '#6B7280' }}>{t('dashboard.happeningToday')}</p>
                    </header>

                    {isLeader && pendingCount > 0 && (
                        <Card
                            onClick={() => navigate('/worship/songs/approvals')}
                            style={{
                                backgroundColor: 'var(--color-brand-blue-light)',
                                border: '1px solid var(--color-brand-blue)',
                                cursor: 'pointer',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'space-between',
                                padding: '16px',
                                marginBottom: '8px'
                            }}
                        >
                            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                <span className="material-symbols-outlined" style={{ color: 'var(--color-brand-blue)', fontSize: '28px' }}>pending_actions</span>
                                <div>
                                    <p className="text-card-title" style={{ color: 'var(--color-brand-blue)', marginBottom: '2px' }}>
                                        {t('songs.dashboard.pendingEdits', { count: pendingCount })}
                                    </p>
                                    <p className="text-overline" style={{ color: 'var(--color-brand-blue)', opacity: 0.8 }}>
                                        {t('songs.moderation.subtitle')}
                                    </p>
                                </div>
                            </div>
                            <span className="material-symbols-outlined" style={{ color: 'var(--color-brand-blue)' }}>chevron_right</span>
                        </Card>
                    )}

                    {pendingMembers > 0 && (
                        <Card
                            onClick={() => navigate('/mainhub/people/approvals')}
                            style={{
                                backgroundColor: 'var(--color-brand-blue-light)',
                                border: '1px solid var(--color-brand-blue)',
                                cursor: 'pointer',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'space-between',
                                padding: '16px'
                            }}
                        >
                            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                <span className="material-symbols-outlined" style={{ color: 'var(--color-brand-blue)', fontSize: '28px' }}>person_add</span>
                                <div>
                                    <p className="text-card-title" style={{ color: 'var(--color-brand-blue)', marginBottom: '2px' }}>
                                        {t('dashboard.pendingRequestsCount', { count: pendingMembers })}
                                    </p>
                                    <p className="text-overline" style={{ color: 'var(--color-brand-blue)', opacity: 0.8 }}>
                                        {t('dashboard.pendingRequestsTitle')}
                                    </p>
                                </div>
                            </div>
                            <span className="material-symbols-outlined" style={{ color: 'var(--color-brand-blue)' }}>chevron_right</span>
                        </Card>
                    )}
                </>
            )}

            {!isMaster && !isPastor && (
                <section>
                    <h3 className="text-h2" style={{ marginBottom: '16px' }}>{t('dashboard.quickActions')}</h3>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '8px' }}>
                        <Card
                            className="flex-center"
                            onClick={() => navigate('/worship/songs/new')}
                            style={{ flexDirection: 'column', padding: '24px 16px', gap: '8px', cursor: 'pointer' }}
                        >
                            <span className="material-symbols-outlined" style={{ fontSize: '32px', color: 'var(--color-brand-blue)' }}>add_circle</span>
                            <span className="text-card-title">{t('dashboard.newSong')}</span>
                        </Card>
                        <Card
                            className="flex-center"
                            onClick={() => navigate('/mainhub/people')}
                            style={{ flexDirection: 'column', padding: '24px 16px', gap: '8px', cursor: 'pointer' }}
                        >
                            <span className="material-symbols-outlined" style={{ fontSize: '32px', color: 'var(--color-brand-blue)' }}>person_add</span>
                            <span className="text-card-title">{t('dashboard.addPerson')}</span>
                        </Card>
                    </div>
                </section>
            )}

            {/* Global Activity Feed for everyone (except guests handled above) */}
            <ActivityFeed />
        </div>
    );
};

