import type { FC, FormEvent } from 'react';
import { useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Card } from '../components/ui/Card';
import { Button } from '../components/ui/Button';

export const ResetPassword: FC = () => {
    const { t } = useTranslation();
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const token = searchParams.get('token');

    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

    const handleSubmit = async (e: FormEvent) => {
        e.preventDefault();
        if (password !== confirmPassword) {
            setMessage({ type: 'error', text: t('auth.passwordsDoNotMatch') });
            return;
        }

        setIsLoading(true);
        setMessage(null);

        try {
            const response = await fetch('/api/auth/reset-password', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ token, password })
            });
            const data = await response.json();

            if (data.success) {
                setMessage({ type: 'success', text: data.message });
                setTimeout(() => navigate('/login'), 3000);
            } else {
                setMessage({ type: 'error', text: data.error || t('auth.resetError') });
            }
        } catch (err) {
            setMessage({ type: 'error', text: t('common.connectionError') });
        } finally {
            setIsLoading(false);
        }
    };

    if (!token) {
        return (
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '100vh', padding: '24px' }}>
                <Card style={{ padding: '32px', textAlign: 'center' }}>
                    <h2 className="text-h2" style={{ color: '#EF4444' }}>{t('auth.invalidToken')}</h2>
                    <p className="text-body" style={{ marginTop: '16px' }}>{t('auth.invalidTokenDesc')}</p>
                    <Button label={t('auth.backToLogin')} variant="ghost" onClick={() => navigate('/login')} style={{ marginTop: '24px' }} />
                </Card>
            </div>
        );
    }

    return (
        <div style={{
            display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
            minHeight: '100vh', padding: '24px', backgroundColor: 'var(--color-ui-surface)'
        }}>
            <div style={{ marginBottom: '32px', textAlign: 'center' }}>
                <span className="material-symbols-outlined" style={{ fontSize: '48px', color: 'var(--color-brand-blue)' }}>password</span>
                <h1 className="text-h1" style={{ marginTop: '16px' }}>{t('auth.resetPasswordTitle')}</h1>
                <p className="text-body" style={{ color: '#6B7280' }}>{t('auth.resetPasswordSubtitle')}</p>
            </div>

            <Card style={{ padding: '32px', width: '100%', maxWidth: '400px' }}>
                <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                    {message && (
                        <div style={{
                            padding: '12px',
                            backgroundColor: message.type === 'success' ? 'rgba(16, 185, 129, 0.1)' : 'rgba(239, 68, 68, 0.1)',
                            color: message.type === 'success' ? '#10B981' : '#EF4444',
                            borderRadius: '12px', fontSize: '14px', textAlign: 'center'
                        }}>
                            {message.text}
                        </div>
                    )}

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        <label className="text-overline" style={{ color: '#6B7280' }}>{t('auth.newPassword')}</label>
                        <input
                            type="password"
                            placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                            className="w-full"
                        />
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        <label className="text-overline" style={{ color: '#6B7280' }}>{t('auth.confirmPassword')}</label>
                        <input
                            type="password"
                            placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                            value={confirmPassword}
                            onChange={(e) => setConfirmPassword(e.target.value)}
                            required
                            className="w-full"
                        />
                    </div>

                    <Button
                        type="submit"
                        label={isLoading ? t('common.loading') : t('auth.updatePassword')}
                        variant="primary"
                        disabled={isLoading}
                        style={{ width: '100%', marginTop: '8px' }}
                    />
                </form>
            </Card>
        </div>
    );
};

import { useState, type FC } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { useTheme } from '../hooks/useTheme';
import { AuthService } from '../services/authService';
import { Card } from '../components/ui/Card';
import { useToast } from '../context/ToastContext';

export const Settings: FC = () => {
    const { user } = useAuth();
    const { t, i18n } = useTranslation();
    const { theme, setTheme } = useTheme();
    const navigate = useNavigate();
    const { addToast } = useToast();
    const { hasRole } = useAuth();
    const [isSaving, setIsSaving] = useState(false);

    const isMaster = user?.role?.name === 'master';
    const canCustomizeInvitations = isMaster || hasRole('pastor') || hasRole('leader') || hasRole('coordinator');

    const handleLanguageChange = async (lang: string) => {
        setIsSaving(true);
        try {
            await i18n.changeLanguage(lang);
            if (user) {
                await AuthService.updateSettings(theme, lang);
            }
        } finally {
            setIsSaving(false);
        }
    };

    const handleThemeChange = async (newTheme: 'light' | 'dark') => {
        setIsSaving(true);
        try {
            setTheme(newTheme);
            if (user) {
                await AuthService.updateSettings(newTheme, i18n.language);
            }
        } finally {
            setIsSaving(false);
        }
    };

    const SettingRow = ({ icon, title, subtitle, onClick, color = 'var(--color-brand-blue)', rightElement }: any) => (
        <Card
            onClick={onClick}
            style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                cursor: onClick ? 'pointer' : 'default',
                padding: '16px',
                marginBottom: '8px',
                opacity: isSaving ? 0.7 : 1,
                pointerEvents: isSaving ? 'none' : 'auto'
            }}
        >
            <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                <div style={{
                    width: '40px',
                    height: '40px',
                    borderRadius: '12px',
                    backgroundColor: `${color}10`,
                    color: color,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center'
                }}>
                    <span className="material-symbols-outlined">{icon}</span>
                </div>
                <div>
                    <p className="text-body" style={{ fontWeight: 600, margin: 0 }}>{title}</p>
                    {subtitle && <p className="text-overline" style={{ marginTop: '2px' }}>{subtitle}</p>}
                </div>
            </div>
            {rightElement ? rightElement : (onClick && <span className="material-symbols-outlined" style={{ color: 'var(--color-ui-text-soft)', opacity: 0.5 }}>chevron_right</span>)}
        </Card>
    );

    return (
        <div style={{ paddingBottom: '40px' }}>
            <header style={{ marginBottom: '24px' }}>
                <h1 className="text-h1">{t('profile.preferences')}</h1>
                <p className="text-body-secondary">{t('dashboard.personalizeExperience') || 'Personaliza tu experiencia en la plataforma.'}</p>
            </header>

            <div className="settings-grid" style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))',
                gap: '32px'
            }}>
                {/* Column 1: Personal & System */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '32px' }}>
                    {/* Account Section */}
                    <section>
                        <h3 className="text-overline" style={{ color: 'var(--color-brand-blue)', marginBottom: '16px', letterSpacing: '1px', fontWeight: 700 }}>{t('profile.account')}</h3>
                        <SettingRow
                            icon="person"
                            title={t('nav.me') || t('profile.title')}
                            subtitle={t('profile.accountSubtitle')}
                            onClick={() => navigate('/profile')}
                        />
                    </section>

                    {/* System Section */}
                    <section>
                        <h3 className="text-overline" style={{ color: 'var(--color-brand-blue)', marginBottom: '16px', letterSpacing: '1px', fontWeight: 700 }}>{t('profile.system')}</h3>
                        <SettingRow
                            icon="palette"
                            title={t('profile.theme')}
                            subtitle={theme === 'dark' ? t('profile.dark') : t('profile.light')}
                            rightElement={
                                <div style={{ display: 'flex', gap: '4px', backgroundColor: 'var(--color-ui-bg)', padding: '4px', borderRadius: '12px' }}>
                                    <div
                                        onClick={() => handleThemeChange('light')}
                                        style={{
                                            padding: '6px 12px', borderRadius: '8px', cursor: 'pointer',
                                            backgroundColor: theme === 'light' ? 'var(--color-brand-blue)' : 'transparent',
                                            color: theme === 'light' ? 'white' : 'var(--color-ui-text-soft)',
                                            transition: 'all 0.2s'
                                        }}
                                    >
                                        <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>light_mode</span>
                                    </div>
                                    <div
                                        onClick={() => handleThemeChange('dark')}
                                        style={{
                                            padding: '6px 12px', borderRadius: '8px', cursor: 'pointer',
                                            backgroundColor: theme === 'dark' ? 'var(--color-brand-blue)' : 'transparent',
                                            color: theme === 'dark' ? 'white' : 'var(--color-ui-text-soft)',
                                            transition: 'all 0.2s'
                                        }}
                                    >
                                        <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>dark_mode</span>
                                    </div>
                                </div>
                            }
                        />

                        <SettingRow
                            icon="translate"
                            title={t('profile.language')}
                            subtitle={t('profile.languageSubtitle')}
                            rightElement={
                                <div style={{ display: 'flex', gap: '6px' }}>
                                    {['es', 'en', 'pt'].map(lang => (
                                        <div
