                            subtitle={t('profile.notificationsSubtitle')}
                            onClick={() => addToast('Pr├│ximamente: Configuraci├│n de notificaciones push y email.', 'info')}
                        />
                    </section>
                </div>

                {/* Column 2: Management & Help */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '32px' }}>
                    {/* Church Administration Section */}
                    {canCustomizeInvitations && (
                        <section>
                            <h3 className="text-overline" style={{ color: 'var(--color-brand-blue)', marginBottom: '16px', letterSpacing: '1px', fontWeight: 700 }}>Gesti├│n de Organizaci├│n</h3>
                            <SettingRow
                                icon="mail_outline"
                                title="Personalizaci├│n de Invitaciones"
                                subtitle="Configura los textos y plantillas de los correos"
                                onClick={() => navigate('/settings/invitations')}
                            />
                        </section>
                    )}

                    {/* Admin Section */}
                    {isMaster && (
                        <section>
                            <h3 className="text-overline" style={{ color: 'var(--color-danger-red)', marginBottom: '16px', letterSpacing: '1px', fontWeight: 700 }}>{t('profile.admin')}</h3>
                            <SettingRow
                                icon="security"
